  (NULL, 'keskkonnaamet', 'teadmata', 58.3708881998299, 24.5450246262108, true, 0, 'Roomasid niiske ilmaga kõnniteel, ilmselt tulnud aedadest, sest teisel pool on ainult tiheda liiklusega sõidutee.', to_timestamp(1595310837561/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4947637012615, 24.8549927811799, true, 0, NULL, to_timestamp(1595310840843/1000.0)),
