  (NULL, 'keskkonnaamet', 'teadmata', 59.4483003428198, 24.838715197909, true, 0, 'Käisin seal matkal 16. juulil. Kogu see ala oli neid vastikuid nälkjaid täis.', to_timestamp(1595310863849/1000.0)),
