  (NULL, 'keskkonnaamet', 'teadmata', 59.3082551278381, 24.4136393128297, true, 0, 'Ilmusid aeda juba 5-6 aastat tagasi. Suveõhtud mööduvad "jahil" käies. Sellel suvel neid elukaid eriti palju, sest talvitusid kenasti meie olematus talves.', to_timestamp(1595310959243/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.3814018259816, 24.6478826879543, true, 0, NULL, to_timestamp(1595310976007/1000.0)),
