  (NULL, 'keskkonnaamet', 'teadmata', 59.4684800433314, 24.9488050839625, true, 0, NULL, to_timestamp(1595311001755/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.3483401204282, 24.9042803468053, true, 0, 'Märja ilmaga tihti palju roomamas kergliiklusteel. Kõrval on valdavalt maha jäetud aiamaa piirkond.', to_timestamp(1595311036851/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.459587415371, 24.8316963196051, true, 0, 'Suures koguses', to_timestamp(1595311037976/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.430906669465, 24.3859920563531, true, 0, NULL, to_timestamp(1595311044700/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4619775514407, 24.6849351863772, true, 0, 'Ilmselt jõudsid teod meie aiani prügimäelt, mis veel mõni aega tagasi tegutses, hetkel on neil mõnus elupaik endise Agro Neeme aiandi territooriumil, kus on kõrge võsa ja territooriumi valda ei ole seal mingit hooldust teinud.', to_timestamp(1595311044927/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4889956764924, 24.8553064115986, true, 0, NULL, to_timestamp(1595311075513/1000.0)),
