  (NULL, 'keskkonnaamet', 'teadmata', 59.5388435758225, 24.8133087158138, true, 0, 'Tere! Eile jalutamas käies, oli teel surnud tigu. Pilti kohe ei teinud, mõtlesin, et tagasitulles teen, aga selleks ajaks oli tigu teelt kadunud. Asukoht Haabneeme, Heldri tee.', to_timestamp(1595311572614/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4293642786468, 24.3907052392097, true, 0, 'Marali tee 6 Vääna-Jõesuu', to_timestamp(1595311617447/1000.0)),
