  (NULL, 'keskkonnaamet', 'teadmata', 59.4653954053677, 24.4150632333049, true, 0, 'Lusitaania teetigu on olnud meie külas alates sellest ajast, kui sinna kolisime ehk aasta 2015. Sellel aastal tundub natuke vähem, aga igal aastal on ikka teedel ja murul näha olnud.', to_timestamp(1595311747777/1000.0)),
