  (NULL, 'keskkonnaamet', 'teadmata', 59.314231919988, 24.5517665398471, true, 0, 'Kuigi hävitan neid igapäevaselt, siis kasvavas trendis - eilne tulemus 100 ringis.', to_timestamp(1595311828068/1000.0)),
