  (NULL, 'keskkonnaamet', 'teadmata', 58.5546429337441, 25.4360961913999, true, 0, 'aastal on neid meie ja naabrite kruntidel, samutikruntidega piirnevas tammikus isegi päeva ajal näha palju. Alates 2018 oleme leidnud üksikuid musta seateo isendeid. Esimest korda leidsime 2020 suure seateo isendeid ja neid näib palju olevat.', to_timestamp(1595313337587/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.3946894348574, 24.3149239496863, true, 0, NULL, to_timestamp(1595313352228/1000.0)),
