  (NULL, 'keskkonnaamet', 'teadmata', 59.4604945055927, 24.8295577378846, true, 0, 'Selle tee peal oli lusitaania teetigusid umbes 10.', to_timestamp(1595313401979/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.3106077885762, 24.664821624749, true, 0, 'Eriti aktiivselt liigub peale vihma. Korjame ca 30-40 tigu päevas.', to_timestamp(1595313409621/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4331800143389, 24.5544113519389, true, 0, NULL, to_timestamp(1595313413355/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4618950525587, 24.4007250919941, true, 0, 'Hetkel ei ole pilte aga Lusitaania tigusi on Suurupis massiliselt. Aias ning teedel.', to_timestamp(1595313421173/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4620850493489, 24.4185350855899, true, 0, 'Ainuüksi oma aias on neid sadu.', to_timestamp(1595313422337/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.3088863228024, 24.6643861963713, true, 0, NULL, to_timestamp(1595313437291/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.369775044904, 24.2657401153192, true, 0, 'Esimest korda märkasime eelmisel suvel, sel aastal väga palju. Korjame naabritega õhtuti nii aiast kui teede äärest. Kõige rohkem lusitaania nälkjaid. On ära söönud lillede redise-, salati-, porgandi jms pealsed, ronivad terassile ja mööda maja seinu:(', to_timestamp(1595313483640/1000.0)),
