  (NULL, 'keskkonnaamet', 'teadmata', 58.5546429337441, 25.4360961913999, true, 0, 'Keila-Joal leiab küllalt lusitaania tigusi, nii pargis, kui teede peal. Kahjuks kaardi peal ei saa ära märkida, kuna kaart on täiesti valge.', to_timestamp(1595315216982/1000.0)),
