  (NULL, 'keskkonnaamet', 'teadmata', 59.3926714497584, 24.3060670440579, true, 0, 'Nende kogus on meeletu! Hoovis palja jalaga käia ei saa üldse.', to_timestamp(1595315241566/1000.0)),
