  (NULL, 'keskkonnaamet', 'teadmata', 58.3998659561302, 24.6666896271829, true, 0, 'Terve aed neid täis. Ilmselt tulevad kõrgepinge liini alt.', to_timestamp(1595319383285/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4936197807517, 24.8651482001251, true, 0, 'Lusitaania teeteod tohututes kogustes, tulevad raudteeäärsete taimede (hein-võsa-muud taimed) poolt.', to_timestamp(1595319461871/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.3095172590227, 24.4003295387082, true, 0, 'Koduaedades ja kõrval asuvas männikus suures koguses. Keskmine päevaga kinnipüütute arv 40-50tk', to_timestamp(1595319484441/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4357749975605, 24.7369140386509, true, 0, 'j6lgid libedad limukad', to_timestamp(1595319493177/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4985241650715, 24.9072833360191, true, 0, 'Invasioon algas paar aastat tagasi, peale kergliiklustee valmimist.', to_timestamp(1595319500176/1000.0)),
