  (NULL, 'keskkonnaamet', 'teadmata', 59.4598198439356, 24.6676665198512, true, 0, 'Süsta pargi Süsta tänava poolne külg kubiseb niiske ilma ajal teetigudest. Pärast heina ära niitmist pargis, päeval tigusid näha pole. Õhtul tulevad taas liikvele.', to_timestamp(1595319704931/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4679517033295, 24.3969864137423, true, 0, NULL, to_timestamp(1595319719878/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3626282204206, 25.6021311685146, true, 0, 'Viljandi Trepimägi trepp oli pärast vihma neid nälkjaid täis. Alguses püüdsime neid lugeda, aga üle 50 isendi puhul läks lugemine juba sassi.', to_timestamp(1595319721875/1000.0)),
