  (NULL, 'keskkonnaamet', 'teadmata', 59.4660778346337, 24.6911916975464, true, 0, 'Kopli liinide kandist kuni paljassaare poolsaareni leidub ohtralt', to_timestamp(1595319765101/1000.0)),
