  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3715267332138, 25.5835978340281, true, 0, 'Mitmes ümbruskondses eramuaias arvukalt lusitaania teetigusid. Esimesed ilmusid 3-4 aastat tagasi, kuid sel aastal on arvukus märkimisväärsaelt tõusnud.', to_timestamp(1595319986029/1000.0)),
