  (NULL, 'keskkonnaamet', 'teadmata', 59.4338426162843, 24.7322785423275, true, 0, 'Tulevad kõrvalt tühjalt maa-alalt Vuti 4, mida kasutatakse puukooli ja aiandina. Vihmase ilmaga õhtuti korjame neid mitusada.', to_timestamp(1595321991700/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4336376580243, 24.5603325662106, true, 0, NULL, to_timestamp(1595322001247/1000.0)),
