  (NULL, 'keskkonnaamet', 'teadmata', 58.3632350402713, 25.5968150895074, true, 0, 'Viljandis, Pika ja Oru tänava vahelisel isetekkelisel jalgrajal leidus ka mitmeid erinevaid - nii kohalikke kui võõraid.', to_timestamp(1595322067127/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 58.4148827463969, 24.4830406198709, true, 0, 'Neid on seal kõvasti. Jalutan seal igapäevaselt koeraga.', to_timestamp(1595322068945/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.385446399999, 24.6710271999996, true, 0, 'Vabaõhumuuseumis olid kõik teed ja rajad vihmase ilmaga neid täis.', to_timestamp(1595322145180/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4438680057405, 24.6015736737477, true, 0, NULL, to_timestamp(1595322156598/1000.0)),
