  (NULL, 'keskkonnaamet', 'teadmata', 59.2171949337627, 24.6848362793452, true, 0, 'ca.10cm pikkune isend teeservas', to_timestamp(1595322404643/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4951681120356, 24.8602005303193, true, 0, 'teetruubi kaldad.', to_timestamp(1595322470486/1000.0)),
