  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4332890209897, 24.3835968824027, true, 0, 'Natukene tumedam, kui on näidisel. On võimalus, et on tavaline suur seatigu, kuna on olemas ka nemad, või juba mõlemate segu.', to_timestamp(1595323070242/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.3571200474897, 24.908200085586, true, 0, 'Jüris, laste tn uues koerteaias', to_timestamp(1595323088463/1000.0)),
