  (NULL, 'keskkonnaamet', 'teadmata', 59.4381636601783, 24.7945254610607, true, 0, 'buradiino moodi aga limane', to_timestamp(1595323333959/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.346625045569, 24.297350074303, true, 0, 'Lusitaania teetigusid on meie piirkonnas tuhandeid, korjame juba mitu aastat kuid järjest hullemaks läheb.', to_timestamp(1595323375666/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 58.5546429337441, 25.4360961913999, true, 0, NULL, to_timestamp(1595323383555/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.42944444, 24.44027778, true, 0, 'Polnud endal eelteadmist, et tegu on kahjuriga. Tõrjusin kaevemeetodil karuputke ning see limusk oli rabarberi suuruse putke varrel.', to_timestamp(1595323396686/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 58.5546429337441, 25.4360961913999, true, 0, NULL, to_timestamp(1595323426651/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.3132230709658, 24.3793025819512, true, 0, NULL, to_timestamp(1595323450507/1000.0)),
