  (NULL, 'keskkonnaamet', 'teadmata', 59.4257269144624, 24.5588356535064, true, 0, 'Eile pärast vihma korjasime aiast 75 lusitaania teetigu', to_timestamp(1595323496514/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4133157701497, 27.5074892555294, true, 0, 'Kokku sain ligikaudu 20 tk. Hetkel on vaikus, ei ole enam neid näha olnud.', to_timestamp(1595323542043/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4361605508366, 24.5467343537282, true, 0, NULL, to_timestamp(1595323558284/1000.0)),
