  (NULL, 'keskkonnaamet', 'teadmata', 59.3162018021455, 24.3839358945121, true, 0, NULL, to_timestamp(1595323647439/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.15945, 23.7402500000001, true, 0, 'Esimesed teod tulid paar aastat tagasi ja kohe hakkasime neid ka korjama. Kuna korjame neid ainult nädalavahetustel siis nüüdseks on asi nii hull, et kaks 5 liitrist nõud saame kindlasti täis.', to_timestamp(1595323650154/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4399369401137, 24.5222826003304, true, 0, 'Suht palju neid siin kandis. 1m2 kohta 1 teo ikka leiab. Korjamine paistab suht mõtetu tegevus, homme on jälle sama palju.', to_timestamp(1595323713895/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4740363111975, 25.1521347732128, true, 0, 'vähemalt 4 tükki parkla juures silla alusega lähedal', to_timestamp(1595323729188/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4717700451015, 24.8792450944331, true, 0, NULL, to_timestamp(1595323738564/1000.0)),
