  (NULL, 'keskkonnaamet', 'teadmata', 59.300466799999, 24.6619675999996, true, 0, '2019 korjasime aiast ja Jõe kaldalt u 2000 tk, tänavu nädalaga 300 tigu.', to_timestamp(1595323826523/1000.0)),
