  (NULL, 'keskkonnaamet', 'teadmata', 59.42738, 24.38014, true, 0, 'Oleme püüdnud neid kokku korjta ja hävitada juba 5 aastat. Jätkame', to_timestamp(1595323989351/1000.0)),
