  (NULL, 'keskkonnaamet', 'teadmata', 59.4991120118967, 24.9074133188714, true, 0, 'Selles kohas asfaldi peal on neid alati näha, ka kuivemate ilmadega.', to_timestamp(1595324183887/1000.0)),
