  (NULL, 'keskkonnaamet', 'teadmata', 59.5046377381726, 24.8540848927794, true, 0, 'Raudteemaa, kuhu veetakse aiandusjäätmeid, on neid massiliselt.', to_timestamp(1595324353900/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.3945918409315, 24.3056330006262, true, 0, 'Keila-Joa Horisondi aiandusühistu. 2019 aastal kinnipüütud isendite arv 900m2 suurusel krundil küündis 12000 kanti. Seda siis Juuni,Juuli,August. Augustis oli juba nälkjaid natukene vähem. See aasta (2020) tundub neid olevat jälle sama palju.', to_timestamp(1595324363767/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.5545559134058, 24.7977304458553, true, 0, NULL, to_timestamp(1595324380612/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4663600000001, 24.38561, true, 0, NULL, to_timestamp(1595324383194/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.3192872294401, 24.5274496078425, true, 0, 'Neid on siin palju ja juba pikemalt on kohalikud neid seal ka havitanud.', to_timestamp(1595324433875/1000.0)),
