  (NULL, 'keskkonnaamet', 'teadmata', 59.3181653273041, 24.550944385637, true, 0, 'Saue tammik on lusitaania tigusid täis. Neid vöib öhtuti korjata sadu, peale vihma tuhandeid.', to_timestamp(1595327609526/1000.0)),
