  (NULL, 'keskkonnaamet', 'teadmata', 58.3681535543056, 26.7980912167547, true, 0, 'Kõrval asub Juhani puukool. Kergliiklustee ääres ning teel leidsime tigusid juba eelmisel aastal.Ka sellel aastal on neid on seal palju.', to_timestamp(1595327880943/1000.0)),
