  (NULL, 'keskkonnaamet', 'teadmata', 59.3858560131973, 24.7196444148433, true, 0, NULL, to_timestamp(1595345639373/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 58.997049996068, 22.7591660730694, true, 0, 'Faasion aiapoest ostetud roniroos "Aloha", Mihkel Saar puukooli toodang.', to_timestamp(1595345721002/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.3051484915683, 24.6682138274108, true, 0, NULL, to_timestamp(1595345759684/1000.0)),
