  (NULL, 'keskkonnaamet', 'teadmata', 59.4313430385802, 24.6753709293641, true, 0, 'Rannaproomenadil, vaatetorni lähedal oli märgatut võõrliik.', to_timestamp(1595347617849/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4361200000001, 24.5154400000001, true, 0, 'Lillesalongi territooriumi ümbrus, kohati arvukalt.', to_timestamp(1595347688149/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4824295015811, 24.9557229219399, true, 0, 'Ise olen naaberkrundi omanik, kuid teod pesitsevad just aadressil Puhkuse tee 31. Omanikud käivad seal väga harva ja seetõttu on tigudele peidukohti piisavalt.', to_timestamp(1595347741655/1000.0)),
