  (NULL, 'keskkonnaamet', 'teadmata', 59.4703568710235, 24.3997131867333, true, 0, 'Рано утром и вечером, когда становится сыро, каждый день собираем в среднем по 120шт.', to_timestamp(1595349460815/1000.0)),
