  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.5546429337441, 25.4360961913999, true, 0, 'Jüri, Rae vald, Ristiku tänav', to_timestamp(1595350871810/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 58.5546429337441, 25.4360961913999, true, 0, 'Palun järgige Eesti põhiseadust. § 52 Riigiasutuste ja kohalike omavalitsuste asjaajamiskeel on eesti keel. Hetkel pool tekstist vene keeles ja ei saa aru mis seal kirjas.', to_timestamp(1595350897809/1000.0)),
