  (NULL, 'keskkonnaamet', 'teadmata', 59.4647347645856, 24.8981191586242, true, 0, '100m teelõigul oli 20 teetigu. Terve Pirita jõeoru kaldad on neid paksult täis.', to_timestamp(1595350982187/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 57.7050226370764, 27.2860767151486, true, 0, NULL, to_timestamp(1595351036631/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 58.5546429337441, 25.4360961913999, true, 0, NULL, to_timestamp(1595351051110/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3481946741474, 24.2947891527242, true, 0, 'Arvukus: >_100. Maksimaalselt korjatud krundilt päevas 210 tigu. Üldkasutataval teel palju. Mürki pole kasutanud.', to_timestamp(1595351069255/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.3090535091681, 24.4114747006871, true, 0, NULL, to_timestamp(1595351230332/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3010101283222, 24.4176450787431, true, 0, 'Peale seda, kui naabri aeda ilmus kaunis magnoolia, hakkas see probleem tasapisi märku andma. Esimesi lusitaanlasi hakksime selt üle tee roomamas märkama aasta möödudes, nüüd olen neid korjanud sadu ja sadu kui mitte tuhandeid.', to_timestamp(1595351345761/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.3084863302118, 24.411750292261, true, 0, NULL, to_timestamp(1595351366774/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.3445756512478, 24.2951917648256, true, 0, 'Vanavanemate suvila seal ja lusitaaniatigusid seal juba mitu aastat ja hästi palju.', to_timestamp(1595351396461/1000.0)),
