  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3360913586077, 24.450016109282, true, 0, 'Neid on musti suuri ja heledaid väikeseid. Meeletu limaga. Eri värvuses ja suuruses, mõni päev ühes kohas kümneid.', to_timestamp(1595358484872/1000.0)),
