  (NULL, 'keskkonnaamet', 'teadmata', 59.4284830265509, 24.6221556165828, true, 0, 'После дождя видели на пешеходной дорожке около 100 штук', to_timestamp(1595358694036/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4822109233622, 24.9299087464328, true, 0, 'Palju on neid, korjame ca. 150 tk igapäevaselt.', to_timestamp(1595358730323/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.8053190452888, 25.4397939636553, true, 0, 'Tigusid on palju ja nad on elanud seal juba mitu aastat.', to_timestamp(1595358745345/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.3415332767081, 24.279485207399, true, 0, 'Meil on neid vága palju. Korjame igapáevasslt.', to_timestamp(1595358811797/1000.0)),
