  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4379206462037, 24.5208434884203, true, 0, 'Tunni ajaga korjatud pool ämbrit. On aktiivsed niiske ja pilvise ilmaga, samuti ööpimeduses.', to_timestamp(1595360184329/1000.0)),
