  (NULL, 'keskkonnaamet', 'teadmata', 59.417626906691, 24.7106909727328, true, 0, 'каждый день между остановками Tedre и Linnu Tee наблюдаются 1-3 светло коричневых испанских слизня выползающих на пешеходную дорожку.', to_timestamp(1595360548048/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 58.8878749420236, 25.5735441890281, true, 0, 'Lisatud Keskkonnaameti määrang: SUUR SEATIGU', to_timestamp(1595360630650/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.407033699999, 27.5971880999995, true, 0, 'Peale vihma, 500ml purk sai täis 30 min.', to_timestamp(1595360646141/1000.0)),
