  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4631279400162, 24.3930177949592, true, 0, 'Очень много слизней.Все вместе собираем. Рядом лес небольшой. А в лесу на тропинках не пройти просто, куча слизней.', to_timestamp(1595361405096/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.5272886818114, 24.8015762257082, true, 0, NULL, to_timestamp(1595361440747/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 58.5546429337441, 25.4360961913999, true, 0, NULL, to_timestamp(1595361526456/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.2212621173875, 24.3594360351497, true, 0, NULL, to_timestamp(1595361530449/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4435124507983, 24.6007955011328, true, 0, 'Leiame igal õhtul kõiki kolme liiki, teeteod siiski ülekaalus. Kuivema ilmaga kolm-nelikümmend, vihmase ilmaga sadakond.', to_timestamp(1595361610192/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4294640919765, 24.4356215000083, true, 0, 'Siin nägin juba paar aastat tagasi, nüüd sellest aastast juba üle tee ronivad', to_timestamp(1595361710143/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3616700535053, 25.5998415888407, true, 0, 'Terve hoov on neid täis, kuna see on lasteaia hoov siis kindlasti pole keegi neid veel märganud, kuna on puhkuse aeg.', to_timestamp(1595361768467/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4255309136844, 24.623271784197, true, 0, '21.07.20 korjatud 20 min 253 tk.', to_timestamp(1595361813559/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 58.347329208024, 26.7007737887394, true, 0, NULL, to_timestamp(1595361899254/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.2404600014196, 24.526812878741, true, 0, 'Eile nägime esimest korda ühtainsat isendit.', to_timestamp(1595361996236/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4110536441445, 24.814098419018, true, 0, 'Rohkelt isendeid metsas liikumas.', to_timestamp(1595362198440/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.3778200446157, 24.781263352665, true, 0, 'Rohkelt isendeid metsas liikumas.', to_timestamp(1595362262808/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.2133065687636, 24.6540164376151, true, 0, 'у меня на участке 100 % ползали большие желтые слизни, пока не видел статью не придавал этому значения, т.к думал что это подвид наших темных слизней! фотографии не делал, т.к в основном они ползают по ночам, как только увижу сделаю фото и пришлю.', to_timestamp(1595362266221/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.3495583741531, 24.9046186752318, true, 0, NULL, to_timestamp(1595362292253/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.2617267239701, 24.8693038346271, true, 0, NULL, to_timestamp(1595362374012/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4297798082438, 24.653873981305, true, 0, 'Väga rohkelt mererannas ca kilomeetri ulatuses. Söömas rannale uhutud adru, pilliroogu ja muud rohelist.', to_timestamp(1595362386971/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.517488532216, 24.8220913115676, true, 0, NULL, to_timestamp(1595362479826/1000.0)),
