  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3378697609646, 24.2682545866939, true, 0, 'Arvukus: 1. Kàbimetsa 11', to_timestamp(1595364097694/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.5546429337441, 25.4360961913999, true, 0, 'Arvukus: >_100. Põldheina tee, Haabneeme, Viimsi vald, Harjumaa. Mina võitlen Mende nälkjatega juba aastaid. Siis veel ei olnud aiandit Haabneemes ega uusarendust. Siis tulid nälkjad meile aeda metsast.', to_timestamp(1595364111911/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.3099552110363, 24.6650178080305, true, 0, 'Väga palju tigusid selles rajoonis eriti jõe ääres', to_timestamp(1595364137005/1000.0)),
