  (NULL, 'keskkonnaamet', 'teadmata', 59.3122666900117, 24.4067105796273, true, 0, 'Kruusatee haigla juurest suunaga Lauluväljaku poole ja lisaks Lauluväljaku ümbruses olevad kergliiklusteed.', to_timestamp(1595364960643/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.3210697311156, 24.3970599915918, true, 0, 'Keila-Mudaaugu kergliiklustee/tee servad, eriti alal peale Bauoffi poodi.', to_timestamp(1595365063219/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 58.5546429337441, 25.4360961913999, true, 0, 'Võõrliik minu kodukohas - Päramäe kalmistu taga juba aastaid. Sel aastal sooja talve tõttu enam elujõulised', to_timestamp(1595365068269/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4296409221934, 24.3859858466439, true, 0, NULL, to_timestamp(1595365136234/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4241242662421, 24.5554863535913, true, 0, 'Arvukus: 11_100. Avastatud esimesed. Korjatud kokku nelja päevaga u 30 suuremat isendit ning lisaks nende väiksemad isendid, mis paiknesid peamiselt musta vaipkatte, kivide all. Eemaldatud kōik vaipkatted ja aiamaa peenrad, samas on aias palju varjulisi kohti', to_timestamp(1595365174687/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4690424480797, 24.9141914699758, true, 0, 'Kalmistu on "aidanud" kõvasti kaasa nende levikule. Kui suudaks neid hävitada viin, siis see aitaks hoida paljunemist ohjase ka terves külas', to_timestamp(1595365176190/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.31443938969, 24.3972370173864, true, 0, 'Keila Terviseradade Ehitajate tee ja Sopsu-Tooma tn poolsem osa (eriti just see metsatee, mis viib välja Sopsu-Tooma tänavale). Aga Terviserajal üldplaanis leidub neid ikka palju.', to_timestamp(1595365197787/1000.0)),
