  (NULL, 'keskkonnaamet', 'teadmata', 59.001221949135, 22.5888574539592, true, 0, 'Lutsitaanlasi on väga palju juba aastaid. Esimesed leiud juba vähemalt 5-6 aastat tagasi. Oleme ka omal initsiatiivil teavituse saatnud e-kirja teel aadressile (saatja: ). Evi Tasa, tel', to_timestamp(1595414175391/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.309111239052, 24.3900934216745, true, 0, 'Keilas väga väga palju', to_timestamp(1595414188445/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4068762771017, 24.6207182240832, true, 0, NULL, to_timestamp(1595414661341/1000.0)),
