  (NULL, 'keskkonnaamet', 'teadmata', 59.4398973076019, 24.3759815880917, true, 0, 'Teod on 2019 aastast juba', to_timestamp(1595415064914/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.454722199999, 24.8547410999996, true, 0, 'õnneks ainult kõrvitsate all, õhtuti leian paar kolm, kokku siiani umbes 15', to_timestamp(1595415311160/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 58.39178, 26.9557400000001, true, 0, NULL, to_timestamp(1595415504636/1000.0)),
