  (NULL, 'keskkonnaamet', 'teadmata', 59.3417275341617, 24.2775334640938, true, 0, 'Neid on väga palju, värvus varieerub erkoranžist tumepruunini', to_timestamp(1595415890379/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 58.0454709322024, 26.4768416684426, true, 0, 'Korjasin kümmekond hommikul', to_timestamp(1595416135389/1000.0)),
