  (NULL, 'keskkonnaamet', 'teadmata', 59.3829131098212, 24.2384530143587, true, 0, 'Õhtuti võib kokku lugeda üle 200 isendi, 5min jooksul', to_timestamp(1595417029564/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 58.3535721318947, 24.5750392222418, true, 0, 'Nädala jooksul oleme oma aiast leidnud 17 lusitaanlast, valdavalt suured 10-15 cm isendid.', to_timestamp(1595417123726/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 58.3995277666704, 24.6679276092786, true, 0, 'Neid tigusid on seal ikka nii palju ja nii suured! Pildi peal on üks keskmise suurusega isend. Häda ongi selles, et see on elektrikaitsevööndi alla kuuluv ala ja seda ei hoolda keegi. Kõik teod rühivad sealt edasi meie hoovi(Muraka 9 ja 11, Sindi).', to_timestamp(1595417138612/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.3124378646686, 24.4077932612659, true, 0, '22.07.20 märgatud peale vihmasadu rohkearvuliselt ( vähemalt 30 tk) lauluväljaku juures kergliiklusteedel', to_timestamp(1595417308753/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.311599894557, 24.4108236807209, true, 0, 'U 10 lusitaania teeteo isendit märgatud 22.07.20 peale vihmasadu männipargi vahelisel kergliiklusteel', to_timestamp(1595417459119/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.311124737174, 24.4352463681615, true, 0, '22.07.20 nähtud ühte musta seatigu Keila autosilla all kergliiklusteel.', to_timestamp(1595417655287/1000.0)),
