  (NULL, 'keskkonnaamet', 'teadmata', 59.3239341641534, 24.5508818985609, true, 0, 'Koduaias umbrohtu sees meeletult palju. Üle 30 leitud varasemalt juba 50 tükki leitud. Õudsad nälkjad.', to_timestamp(1595422170710/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 58.3896950531703, 26.5831650591377, true, 0, NULL, to_timestamp(1595422310410/1000.0)),
