  (NULL, 'keskkonnaamet', 'teadmata', 59.3104250306778, 24.4149450745503, true, 0, 'Pildil tigu, mille tapmiseks on kasutatud soola. Jälgime, täna oli see tigu aias esimene.', to_timestamp(1595428094276/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4389003891961, 24.5205200065477, true, 0, 'Aed paksult täis teetigusid. Lisaks naabruses Harku valla maa, kus rohtu ei niideta.', to_timestamp(1595428134596/1000.0)),
