  (NULL, 'keskkonnaamet', 'teadmata', 59.528910044827, 24.7976800821711, true, 0, 'leidsin korraga 33 lusitaania teetigu täna õhtul', to_timestamp(1595446731656/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4585351870131, 24.4482172209107, true, 0, NULL, to_timestamp(1595446811760/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.384075644188, 24.8181657611089, true, 0, NULL, to_timestamp(1595446812432/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.3573416141515, 24.6035752091876, true, 0, 'Metsatukast ilmusid õhtul 21 paiku nähtavale, ilmselt oli neid seal rohkem - tol hetkel tee peal oli 6 tk', to_timestamp(1595446843092/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.3161201129699, 24.5641377041811, true, 0, NULL, to_timestamp(1595446878807/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 58.3617313044645, 25.6006956000161, true, 0, NULL, to_timestamp(1595447016538/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 58.3750017218266, 25.6001635290448, true, 0, NULL, to_timestamp(1595447102081/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 58.3679280997537, 25.5804305254679, true, 0, NULL, to_timestamp(1595447627305/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.3659728357656, 24.5917146703875, true, 0, 'Neid oli seal ikka sadakond tee peal, polnud ruumi eriti astudagu, ilma et mõnele peale ei astuks.', to_timestamp(1595447639183/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4322070518036, 24.379924864805, true, 0, 'Olen neid korjanud kevadest alates pea iga õhtu. Kogused sõltuvad kas on vihmane või kuivem perrjood. Enamjaolt saan neid ühe õhtuga 200 kuni 300 tükki. Selle aasta rekord oli üle 500.', to_timestamp(1595447803453/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.391051199999, 24.6607833999996, true, 0, NULL, to_timestamp(1595447997354/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4228914465828, 24.5971633776469, true, 0, NULL, to_timestamp(1595448122784/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4285212230167, 24.3964730707113, true, 0, NULL, to_timestamp(1595448136107/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.364028434069, 24.612749744427, true, 0, NULL, to_timestamp(1595448250898/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4708313873881, 24.8961857000915, true, 0, NULL, to_timestamp(1595448288740/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4131367067724, 24.3124531664693, true, 0, 'Oleme korjanud neid kümnete kaupa tänavu suvel. Eelmisel sügisel nägin ühte aias. Ühist listis oli info Lusitaanlaste kohta 2017 kevadel juba...', to_timestamp(1595448371702/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4258600000001, 24.6602800000001, true, 0, 'Lapsed leidsid sissepääsu lähedalt muru seest. Pilti unustasime teha', to_timestamp(1595448458119/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 58.5546429337441, 25.4360961913999, true, 0, 'Tabasalu. Keskkonnaameti lisatud määrang: MUST SEATIGU', to_timestamp(1595448883300/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 58.5546429337441, 25.4360961913999, true, 0, 'Lôikuse 1 ja 1a Viljandi', to_timestamp(1595449031551/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 57.952843321741, 21.9991567653345, true, 0, NULL, to_timestamp(1595449514161/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4167867781994, 24.7013025116826, true, 0, NULL, to_timestamp(1595449629698/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 57.951540438478, 22.0004553820767, true, 0, NULL, to_timestamp(1595449661132/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4382757781667, 24.5198978922636, true, 0, NULL, to_timestamp(1595450438688/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.394223022351, 24.200123676311, true, 0, 'Tigu leitud salatipeenrast', to_timestamp(1595450508840/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4798019167927, 24.8423778535122, true, 0, NULL, to_timestamp(1595450521012/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.410514667414, 24.6030907460758, true, 0, NULL, to_timestamp(1595450651125/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.3832639872301, 24.2391248533701, true, 0, 'Meie oleme oma aiast Lusitaania teetigusid leidnud juba rohkem kui 5 aasta jooksul, igal aastal järjest rohkem. Sel aastal on tavapärane ühe õhtuga 800 ruutmeetrisest aiast leida 200-300 eksemplari.', to_timestamp(1595450671671/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 58.7985193987277, 25.4238325571614, true, 0, NULL, to_timestamp(1595451030697/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.436992481523, 24.3742839136725, true, 0, 'Selles kandis on neid väga palju, aedades ja teedel, eriti palju peale vihma.', to_timestamp(1595451111696/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4716132967194, 24.9334566070459, true, 0, NULL, to_timestamp(1595451158003/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.462439409041, 24.3917332903572, true, 0, 'Terve Järsaku tee Suurupis on tigusid täis.', to_timestamp(1595451369260/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 58.5546429337441, 25.4360961913999, true, 0, NULL, to_timestamp(1595451845045/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4757695141304, 25.1521385825978, true, 0, NULL, to_timestamp(1595451938434/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4181024884807, 24.6982173586591, true, 0, NULL, to_timestamp(1595452380265/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.4374300000001, 22.8760300000001, true, 0, 'Leitud ühe aiandi lähedal olevast külast. Väga limane tegelane.', to_timestamp(1595452448674/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 58.3883525386076, 26.7368851691415, true, 0, NULL, to_timestamp(1595452619413/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.3780105263763, 24.7858783733622, true, 0, NULL, to_timestamp(1595453883431/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.482831903889, 24.929483640438, true, 0, '1) Nagu te olete vist aru saanud, siis Põhja-Harjumaa rannikuäärsed maa-alad on neid täis. Inimeste aiad kindlasti, ent mind huvitaks rohkem millistesse metsadesse nad Harjumaa põhja osast allapoole vaadates jõudnud on. Vaja oleks nende levikut piirata.', to_timestamp(1595454188036/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.5226033558346, 24.8905699146787, true, 0, '2) Kindlasti info kogumine on raske ja mul on heameel, et te antud teatamise küsimustiku olete loonud ja ma loodan, et see ei ole loodud lihtsalt inimeste rahustamiseks, vaid, et selle põhjal saab ka reaalseid samme astuda.', to_timestamp(1595454251155/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.5035469041943, 24.8275011697576, true, 0, '3) Soovitused: 1) Kui saab tõesti piiridest aru, kus antud isend on rohkem levinud, siis kindlasti seal teha rohkem infojagamise tööd elanikele, et nad hakkaksid äärmise hoolikusega ja koheselt korjama või neile mugaval moel hävitama.', to_timestamp(1595454292763/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4704678376424, 24.4348517611887, true, 0, '4) 2) Teha pistelist kontrolli väljamaalt tulevatele istikutele, mis maanduvad meie puukoolides ja muudes taimi müüdavates ettevõtetes. Ka neil on niisamuti vaja teadlikkust tõsta antud isendi ohtlikkuse üle.', to_timestamp(1595454342747/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4769451858912, 24.8742309173578, true, 0, '5) Isiklikult olen ma korjanud antud isendit kolmel hooajal järjest ja ma ei korja neid see aasta rohkem või vähem, ikka öö jooksul 50-100 tükki. Kui paar päeva järjest korjata, siis on tulemust näha ja suure tõenäosusega arvukus aias väheneb.', to_timestamp(1595454598509/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 58.3600138217961, 25.5995557823482, true, 0, NULL, to_timestamp(1595455903133/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4067315839859, 24.6215965471951, true, 0, NULL, to_timestamp(1595456021037/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.3393256261144, 24.6471666990125, true, 0, NULL, to_timestamp(1595456379562/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 58.996732202888, 22.7435019933254, true, 0, NULL, to_timestamp(1595456864193/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4517028939032, 24.4445436320065, true, 0, 'ühe õhtuga 400 tigu leitud', to_timestamp(1595457712583/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4503041684347, 24.5850145962633, true, 0, NULL, to_timestamp(1595459536623/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4390332088756, 24.873301034803, true, 0, 'Видела 2 жёлтых испанских слизней на своей клумбе под кустом гортензии.', to_timestamp(1595461261057/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4200185877347, 24.6624318951373, true, 0, 'Talllinna loomaaias on teettigusid palju. Ehk levib sealt müüdava kompostmullaga.', to_timestamp(1595473558759/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.482716399999, 24.8782454999996, true, 0, NULL, to_timestamp(1595476838621/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 58.8069522834344, 25.4371011286491, true, 0, 'Suured nälkjad ründavad!!!', to_timestamp(1595478649970/1000.0)),
