  (NULL, 'keskkonnaamet', 'teadmata', 59.4389819962785, 24.8831587683001, true, 0, 'Ходим гулять с собакой за дома на раадику. Там этих слизняков тьма тьмущая !', to_timestamp(1595624609076/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4824260857882, 24.8817002215401, true, 0, NULL, to_timestamp(1595625043563/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4592701377393, 24.6846927475969, true, 0, '3 года боремся с нашествием слизней,собираем вёдрами.Раньше обитали у берега моря,теперь и в садах и в дом ползут.', to_timestamp(1595625477415/1000.0)),
