  (NULL, 'keskkonnaamet', 'teadmata', 59.4366357181857, 24.3643407395217, true, 0, 'Neid on palju, suuremad 20cm, väiksemad (ilmselt veel noored) 4-5cm pikad.', to_timestamp(1595664250002/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4109650372579, 24.6021351006823, true, 0, 'Harkujärvel massiliselt, peale vihma võiks lausa kühvliga neid kokku ajada.', to_timestamp(1595664294538/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.44117717855, 24.8168088645712, true, 0, 'Jalutasin koeraga. Tapsin 18tk. Neid on seal palju.', to_timestamp(1595665218551/1000.0)),
