  (NULL, 'keskkonnaamet', 'teadmata', 59.4300619603151, 24.3885507491801, true, 0, 'На участке уже не осталось улиток, слизни их сжирают. Ходим собираем по утрам и вечерам и в солёную воду кладём. Ходить и собирать можно до Бесконечности. один круг по периметру пройдёшь соберешь ведро, следущий круг столько же и т.д. до бесконечности.', to_timestamp(1595685015362/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.434793614011, 28.0560905576145, true, 0, NULL, to_timestamp(1595685307191/1000.0)),
