  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3061554568383, 24.6653457566469, true, 0, 'Eelmisel aastal oli tigusid väga ohtralt, juba siis korjasime kokku ja hävitasime. Sellel aastal on igapäevane arvukus väiksem, aga tigusisid korjan kokku iga päev.', to_timestamp(1595705911472/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4829599570551, 24.9949629267748, true, 0, 'Suurem hulk Lusitaania teetigusi.', to_timestamp(1595706319525/1000.0)),
