  (NULL, 'keskkonnaamet', 'teadmata', 59.4260199844577, 24.5579509298641, true, 0, 'Tühi krunt, sealt tuleb suurem osa teetigusid naaberkrundile.', to_timestamp(1595956384173/1000.0)),
