  (NULL, 'keskkonnaamet', 'teadmata', 58.8452896182428, 22.7917591701591, true, 0, 'Need olid tee ääres ja üsna väikesed. Aga kollane limarada oli taga', to_timestamp(1596298158968/1000.0)),
