  (NULL, 'keskkonnaamet', 'teadmata', 59.3639225451505, 24.6127869835945, true, 0, 'Keset teerada liikus', to_timestamp(1596303250780/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4226536345542, 24.5649181796864, true, 0, 'Tühja krundi ääres on pärast vihma näha väga palju tigusid. Korjasime ja surmasime 30. augustil vähemalt 50. Värvus tumepruunist oranzhikani, erinevas suuruses.', to_timestamp(1596303927552/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.442188799999, 24.9068116999996, true, 0, 'Mustvseatigu', to_timestamp(1596305052968/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.464893499999, 24.3583234999996, true, 0, 'Asukohas 4+ isendit', to_timestamp(1596306236155/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.464893499999, 24.3583234999996, true, 0, '40-100 isendit vähemalt. Suure tõenäosusega rohkem.', to_timestamp(1596306907567/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.3846392526546, 24.4748139381326, true, 0, 'Metsas mustikate vahel.', to_timestamp(1596307177385/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 58.5546429337441, 25.4360961913999, true, 0, 'Tere! Kas tema on kohalik või lusitaanlane?Aitähh!', to_timestamp(1596308533802/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.368004734581, 25.1743152953518, true, 0, NULL, to_timestamp(1596309528107/1000.0)),
