  (NULL, 'keskkonnaamet', 'teadmata', 59.5572465173099, 24.7964496024504, true, 0, 'Kōnniteel enne Rohuneeme tee 136 maja, pärast Annuse tee pöörak.Ja veel Rohuneeme 130 kõnniteel', to_timestamp(1596316603722/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 58.0499801182781, 26.480580101045, true, 0, NULL, to_timestamp(1596316948224/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.322749599999, 26.1804814999996, true, 0, '100% pole kindel. Meil ka mustad seateod, ei tea, millised nende noored. Olid noored, väiksemad. Ärrituse peale tõmbusid kerra, anumasse jäi kollane lima ja hingamisava tundus olevat ees. Hea, kui saaks kindla vastuse.', to_timestamp(1596319239121/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 58.3626865690605, 26.6614414643057, true, 0, 'Terve kõnnitee äär on täis võõrliiki teetigusid.', to_timestamp(1596347591130/1000.0)),
