  (NULL, 'keskkonnaamet', 'teadmata', 59.0029139166078, 24.7994377827814, true, 0, 'Raplas, Viljandi mnt 12-22 aia tagused ja kõnnitee öösel tigusid täis. Kahjuks eiolnud telefoni kaasas et pildistada. Julgen öelda et ligi 20 tk oli kindlasti kõnitee peal näha.', to_timestamp(1596434350639/1000.0)),
