  (NULL, 'keskkonnaamet', 'teadmata', 59.500249731368, 24.8587593242145, true, 0, 'Üks suur täiskasvanu ja hulgem väiksemaid. Sai kokku korjatud nii palju kui silm võttis ja soolaga purgis hävitatud', to_timestamp(1596565933393/1000.0)),
