  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3700546859355, 24.5448975838787, true, 0, 'Pärnu linn, Metsa 15/17 vastas territooriumil on neid väga palju', to_timestamp(1596567429177/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4757336336069, 25.0289078036402, true, 0, 'Leidub väga palju.', to_timestamp(1596567444824/1000.0)),
