  (NULL, 'keskkonnaamet', 'teadmata', 59.4415277924931, 24.5881527286963, true, 0, '6tk aias kinni püütud ja hukatud', to_timestamp(1596567936029/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4632000520188, 24.6856931618814, true, 0, 'Nei on tuhandetes.', to_timestamp(1596568057398/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4892224494937, 24.8543693241017, true, 0, 'Tigude massiline liikumine Tallinnas Meriväljal Ranniku teel kõnniteel, mis asub peale Merivälja pansionaati väikse metsasalu kõrval.', to_timestamp(1596568146555/1000.0)),
