  (NULL, 'keskkonnaamet', 'teadmata', 59.0043215089998, 24.7969661516372, true, 0, NULL, to_timestamp(1596570978926/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3061433881332, 24.6659085218093, true, 0, 'Jõe ääres on sadu Lusitaania teetigusid. Tegemist on valla maaga, kuid püüame korjata ja hävitada nii nagu jõuame ning niita muru.', to_timestamp(1596571010230/1000.0)),
