  (NULL, 'keskkonnaamet', 'teadmata', 59.4216149099667, 24.5660337884241, true, 0, 'Suur korralikult niitmata ala. Puuvilja juures meeletult noori lusitaania tigusid. Kui ka kohalike Seatigusid.', to_timestamp(1596575120104/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.3670217427831, 24.2658223156563, true, 0, NULL, to_timestamp(1596575186552/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4218970122322, 24.5643104528948, true, 0, 'Keskmises mõõdus lusitaania teod. Maja sissesõidutee kubises ja kõrval jällegi niitmata ala, kus oli palju', to_timestamp(1596575348771/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4067863714039, 24.6177985918827, true, 0, NULL, to_timestamp(1596575427489/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3012368659487, 24.4335708730286, true, 0, 'Need on väga palju ümber maja ronivad kasvuhoone,igale poole. Korjame need igapäev iga õhtu liitrise 2 konistrid täis.', to_timestamp(1596576717412/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4796543273426, 24.8834819411505, true, 0, 'Lepiku 41, Tallinna kandis püüdsime ja tõrjusime üle 200 Lusitaania teeteo perioodil.', to_timestamp(1596589801286/1000.0)),
