  (NULL, 'keskkonnaamet', 'teadmata', 59.3526539560684, 27.4293954328438, true, 0, 'Jõhvi, Pargi tn. Keskkonnaameti lisatud määrang: SUUR SEATIGU', to_timestamp(1596608171179/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.5317165631899, 24.8620505077233, true, 0, 'Mitu tigu ületamas kergliiklusteed Kelvingi/mere suunal.', to_timestamp(1596608555585/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.5132239857753, 24.8502798224722, true, 0, 'Väga palju tigusid, vihmase ilmaga korjame. Üle saja teo ühe korraga.', to_timestamp(1596609389609/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4235334213011, 24.7119603938999, true, 0, NULL, to_timestamp(1596609516465/1000.0)),
