  (NULL, 'keskkonnaamet', 'teadmata', 59.354910265398, 26.3725937295916, true, 0, 'Olen leidnud üksikuid ja hävitanud. Nad tulevad värkelt niidetud murule. Midagi ära pole söönud, isegi aedsalat on alles ja mädarõikapöösas. Eile oli uduvihmane ilm ja siis leidsin õuealalt viis suurt isendit.', to_timestamp(1597428297228/1000.0)),
