  (NULL, 'keskkonnaamet', 'teadmata', 59.5062922363531, 24.8129891365784, true, 0, 'Käisin seal 21.augusti hommikul. See oli mitmenda palava päeva algus. Kokku nägin ca 10 tigu. Käisin samas ka nii 2 nädala eest ja siis oli pilt viitas kuna tigusid oli nii palju et vaevalt sai 1,5 sammu astuda ilma et oleks kellegile otsa astunud.', to_timestamp(1598028696237/1000.0)),
