  (NULL, 'keskkonnaamet', 'teadmata', 58.1142678207377, 25.5722197360707, true, 0, 'Ärritunult tõmbas kerra. Hingamisava kilbi eesosas. Oranži lima ei tuvastanud. Tagantjärgi saame aru, et see tigu on meil juba aastaid olnud. Oleme märganud paar kuni 10 isendit aastas. Nüüd lõpuks süvenesime rohkem ja tegime juhiste järgi liigi kindlaks.', to_timestamp(1600591114155/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 58.659601799999, 23.1747560999996, true, 0, 'FOTOGA', to_timestamp(1600667894373/1000.0)),
