  (NULL, 'keskkonnaamet', 'teadmata', 59.5560719957031, 24.7946602803337, true, 0, 'Lusitaania teetigu esineb Rohuneeme tee ääres kogu Karikakra tee ja Kalmistu tee vahelisel lõigul. Leviala 2020 suvega klasvanud.', to_timestamp(1606314624291/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.5471821246377, 24.8073846799007, true, 0, 'L. teetigu esineb Niidu tee - Aasa põik vahelisel lõigul metsaservas ja elektriliini alusel rohealal. 2020 suvel jägitav leviku laienemine. Oleme püüdnud 2020 hilissuvel leviku vastu võidelda nende regulaarse (2x nädalas) ärakorjamisega.', to_timestamp(1606315075004/1000.0)),
