  (NULL, 'keskkonnaamet', 'teadmata', 57.9529979328513, 26.8358763748053, true, 0, 'Asukoht: Erastvere küla Soodoma talu. Võitlen nendega juba üle 15 aasta. Kuna talu asub eraldi. ei ole mujal külas neid teadaolevalt levinud. Korjan neid igal hommikul ja õhtul kuuma soolvette, hullematel päevadel hommikul ca 500 ja õhtul samapalju.', to_timestamp(1617272023986/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4654357989624, 24.4148677514935, true, 0, 'Lusitaanlad on meie regioonis vähemalt aastast. Levik on suur.', to_timestamp(1617784768479/1000.0)),
