  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3780276281542, 24.7861815387971, true, 0, 'Arvukus: >_100. Vana-Järveküla tee ja Kurnaoja tee peal ja tee ääres heina sees ja metsas. Arvukus on väga suur!', to_timestamp(1627583895901/1000.0)),
