INSERT INTO public.observations (user_id, source, species, lat, lng, present, killed_count, note, observed_at) VALUES
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4867800521517, 24.8660542481052, true, 0, 'Arvukus: 2_10. Nägin tigusid mööda jalutades kahel õhtul samas kohas keset teed. Ühel korral oli näha 2 tigu, teisel korral üks.', to_timestamp(1627648327516/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3467468024266, 24.2930625625162, true, 0, 'Arvukus: >_100. Lusitaania teeteo arvukus selles piirkonnas on kohutavalt suur. Inimesed korjavad küll oma aiast, kuid metsa alt ei hävita neid keegi.', to_timestamp(1627651683096/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4001788203168, 24.3081682780636, true, 0, 'Arvukus: >_100. Meeletult palju, hävitavat saagi.', to_timestamp(1627657834785/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3093444589854, 24.664436280584, true, 0, 'Arvukus: >_100.', to_timestamp(1627660824130/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3527058866744, 24.902871698135, true, 0, 'Arvukus: >_100.', to_timestamp(1627661321680/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.376317899999, 24.9512497999996, true, 0, 'Arvukus: >_100.', to_timestamp(1627664913252/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.4124486467161, 24.4902132369233, true, 0, 'Arvukus: >_100. Peale vihma on maapeal väga palju, nagu maa seest tulevad.', to_timestamp(1627665795610/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.356973821926, 24.2538482158333, true, 0, 'Arvukus: 11_100.', to_timestamp(1627672258556/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3833729852092, 24.8194240645801, true, 0, 'Arvukus: 11_100. Suur niitmata krunt, kuhu teod on edasi liikunud. Veel eelmine aasta olid nad vaid Vana-Järveküla tee ja Vibu tee vahelisel lõigul ainult. Nüüd siis invasioon hoogsalt edasi liikumas Kindluse tee suunas :(', to_timestamp(1627672515301/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.42738, 24.38014, true, 0, 'Arvukus: 11_100.', to_timestamp(1627673966648/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 58.5306568599264, 27.1388483047415, true, 0, 'Arvukus: 2_10. Nägin 2 tk juunis Alatskivi lähedal metsas (Kv. AK118 eraldis 15). Eeldan et nad on kohalikud. Lisatud Keskkonnaameti määrang: MUST SEATIGU', to_timestamp(1627678151441/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.3515019495634, 24.8932868242197, true, 0, 'Arvukus: 1. Kummalist liiki nägin antud asukohas. Kui teate, mis liigiga tegu ja kui ohtlik see on, palun andke mulle ka teada. Lisatud Keskkonnaameti määrang: SUUR HARKSABA röövik', to_timestamp(1627681003011/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4380465761406, 24.5593529611437, true, 0, 'Arvukus: 2_10.', to_timestamp(1627704483732/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4380023469259, 24.5593677389249, true, 0, 'Arvukus: 2_10.', to_timestamp(1627704620737/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4378186399615, 24.5596571438219, true, 0, 'Arvukus: 2_10.', to_timestamp(1627705314170/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4375673196197, 24.5599429750773, true, 0, 'Arvukus: 2_10.', to_timestamp(1627705756985/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3638033545719, 24.0617728664977, true, 0, 'Arvukus: 2_10.', to_timestamp(1627714528793/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 58.3563100000001, 25.5936800000001, true, 0, 'Arvukus: 2_10. 1.juunil lillepoest ostetud Hortensia potitaim, hallikas nälkjapoeg, pea ei ole must, elab potis, pilt moonutab värve, potis paistis veel mune.', to_timestamp(1627726359296/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.365720605662, 26.7900603689791, true, 0, 'Arvukus: 2_10.', to_timestamp(1627728293054/1000.0)),
