  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3626444720123, 24.6390077590266, true, 0, 'Arvukus: 11_100. Leidsime tegelikult rohkem, kuid ei hakanud kõikidest pilti tegema. Oli ka üks eesti must seatigu.', to_timestamp(1627754392890/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.2043177832682, 24.334669556477, true, 0, 'Arvukus: >_100. Kindlasti on neid üle 100, kõiki üles ei leidnud.', to_timestamp(1627757700451/1000.0)),
