  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4706549904922, 24.9353646309865, true, 0, 'Arvukus: >_100. Orasheina tee ja Hellerheina tee ristmikul tehtud pildid. Samuti on tigusid Hellerheina tee 68 krundi piiril.', to_timestamp(1660336181664/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4363853553837, 24.6360058511137, true, 0, 'Arvukus: 11_100. No neid on siin ikka niipalju et peav vaatama, kuhu astua üldse saab, et need jalgealla ei jääks', to_timestamp(1660414197021/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3887790300503, 24.659238484497, true, 0, 'Arvukus: 1.', to_timestamp(1660500932573/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3401927153517, 24.3880126759694, true, 0, 'Arvukus: 2_10. Ei märganud pilti teha, aga oranzi värvi tõttu olen veendunud, et tegemist oli võõrliigiga.', to_timestamp(1660501217671/1000.0)),
