  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.444713759329, 24.3699583411156, true, 0, 'Arvukus: 2_10. Paar nädalat tagasi leidsime aia servast esimesed 3 sellist tigu. Panime üles õllepüünise, saime veel ühe kätte ja siis oli vaikus. Täna hommikul leidsin keset muru platsi erinevatest kohtadest veel 3. Kõik ca 15 cm pikkused. Hävitasin soolvees.', to_timestamp(1661411164296/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.465351576018, 24.4303338519918, true, 0, 'Arvukus: 11_100. Paar aastat tagasi polnud siin ühtegi. Tänavu eriti rohkelt. Peale vihma korjame kümnete kaupa kokku. Vahepeal üksikuid.', to_timestamp(1661449440849/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.6513407524708, 26.5901151560403, true, 0, 'Arvukus: 2_10.', to_timestamp(1661580117030/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3372412212698, 26.0629779335622, true, 0, 'Arvukus: 1. Siinkandis esimene kinlate tunnustega. Eelmisel aastal damal ajal olu ka üks sarnane leid, aga siis me polnud kinlad', to_timestamp(1661582192939/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3932606671137, 24.7319806419228, true, 0, 'Arvukus: 11_100.', to_timestamp(1661710392600/1000.0)),
