  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.6535297884113, 26.5963543591984, true, 0, 'Arvukus: 2_10.', to_timestamp(1661792456183/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.5222674867661, 24.8045105435518, true, 0, 'Arvukus: 11_100.', to_timestamp(1661795936387/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.4061144241305, 26.6984310838987, true, 0, 'Arvukus: >_100. Kohutavalt palju suuri hispaania teeteo isendeid. Ainuüksi tee pealt võis loendada 30 ringis. Kõrvale jääb niiske ja võsastunud ala.', to_timestamp(1661847743669/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3562629108296, 25.0767345387026, true, 0, 'Arvukus: 2_10. Teade aadressile: Võivad olla tulnud alevikust (kus neid on varem märgitud) või värskelt uue haljastuse rajamisega (puud, põõsad) - bensiinijaama rajamine Tallinna mnt 42 kinnistule.', to_timestamp(1661859807338/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3441952035003, 24.5799208381605, true, 0, 'Arvukus: 2_10.', to_timestamp(1661965808638/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4630795689463, 24.4447141575883, true, 0, 'Arvukus: 11_100. Fotol on tigu labida peal.', to_timestamp(1662013127963/1000.0)),
