  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.5546429337441, 25.4360961913999, true, 0, 'Arvukus: 1. Umbes 6 cm pikk, oranzide äärtega, alt hallikas (all keskel selgelt eristatav heledam triip), kokkutõmbudes peaaegu ümar tomp halli alumise osaga, eritas tihket lima.', to_timestamp(1663827796495/1000.0)),
