  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3106407398566, 24.5217989345409, true, 0, 'Arvukus: 1. Fotot ei taibanud enne hävitamist teha, aga tunnused olid ca 12cm pikkus, selgelt oranzi-musta triibuline alaserv, hingamisava kilbi peapoolsel poolel. Pilt tehtud peale labidaga löömist ja munade hirmus keeva vee kallamist.', to_timestamp(1664622341447/1000.0)),
