  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3399398038056, 24.2736830582256, true, 0, 'Arvukus: 2_10. Palun vahetage välja Lusitaania teeteole viitav tekst https://arcg.is/WSvyW0 ja mujal ameti viidetes. A. lusitanicus pole isegi väga lähedane sugulane invasiivse hispaania teeteo A. vulgaris’ega vt https://en.wikipedia.org/wiki/Arion_lusitanicus#Taxonomy', to_timestamp(1681740800869/1000.0)),
