  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3516860635177, 24.9006206128118, true, 0, 'Arvukus: 11_100. Mais 2023 tapetud üle kümne teeteo. Väga suuri isendeid veel pole.', to_timestamp(1685302536960/1000.0)),
