  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.0104183693444, 23.5322171578381, true, 0, 'Arvukus: 2_10. Pürksi küla, Kuuse talu. Esimest korda leitsime oma suvekodu õuest Hispaania teod. Kokku püüdsime ja hävitasime 10 tk.', to_timestamp(1690132938958/1000.0)),
