  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.5546429337441, 25.4360961913999, true, 0, 'Arvukus: 11_100. Leitud ca 20+ isendit, tunduvad noored - hävitatud tules', to_timestamp(1690220108594/1000.0)),
