  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3824045403779, 24.5784896260959, true, 0, 'Arvukus: 11_100. Испанский слизень в Виймси парке', to_timestamp(1690306884905/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.2743403235697, 27.0214199647898, true, 0, 'Arvukus: 11_100.', to_timestamp(1690317647837/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.5546429337441, 25.4360961913999, true, 0, 'Arvukus: 11_100. 2021 - leidsin 1 isend; 2022 märkasin 4 ja sel aastal olen leidnud juba üle 10 isendi. Arvan, et aeda sattusid ehituspoest ostetud mullaga.', to_timestamp(1690359215837/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.2170521817521, 24.6683580279881, true, 0, 'Arvukus: 11_100.', to_timestamp(1690395015230/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.2415929291698, 22.4976216347591, true, 0, 'Arvukus: >_100. Terviserajal oli neid kindlasti üle saja... Peale vihma oli rajal igas suuruses Hispaania teetigusid.', to_timestamp(1690400239615/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.2409731724584, 22.499396518601, true, 0, 'Arvukus: 11_100. Peale vihma oli terviserajal Hispaania teetigusid väga palju.', to_timestamp(1690400653643/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.2420797640227, 22.4962866981522, true, 0, 'Arvukus: 11_100. Terviserada oli tihedalt täis.', to_timestamp(1690401169716/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.2426195079288, 22.4957110473615, true, 0, 'Arvukus: 2_10.', to_timestamp(1690401363224/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4569208823287, 24.9092971029512, true, 0, 'Arvukus: 11_100. Утром на скошенной траве у реки', to_timestamp(1690438645500/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3677061606979, 24.5933822563819, true, 0, 'Arvukus: 11_100. Esimesed leiud mõni päev tagasi, iga päev leiame nüüd neid juurde.', to_timestamp(1690451872136/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3674534044077, 24.2650123146665, true, 0, 'Arvukus: >_100.', to_timestamp(1690459274177/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.1708943707303, 26.3228562435631, true, 0, 'Arvukus: 11_100. Tartu valga maantee ääres põhiliselt meie krundil.', to_timestamp(1690483978658/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3841792836367, 24.2456624024558, true, 0, 'Arvukus: 2_10. Varasematel aastatel pole siin tänavas kohanud neid, nüüd oli kohe palju', to_timestamp(1690655851443/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.652844399999, 26.5943691999996, true, 0, 'Arvukus: 2_10.', to_timestamp(1690697412877/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.5546429337441, 25.4360961913999, true, 0, 'Arvukus: >_100. Neid oli väga väga palju. Värvilt tumepruunist kuni kollaka-oranžini. Mõnes kohas lausa 7-10tk koos. Mööda Kassisaba Pikale tn ja sealt alla järve poole täiesti täis.', to_timestamp(1690749556715/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.9576750548761, 24.8207023599281, true, 0, 'Arvukus: >_100.', to_timestamp(1690790376235/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.4764416656826, 24.5352424031978, true, 0, 'Arvukus: >_100.', to_timestamp(1690823657392/1000.0));
