  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3776387718425, 25.1924539962005, true, 0, 'Arvukus: 11_100. Varem pole kalmistul neid kohanud, aga nüüd oli neid palju ühes kohas, haljastusjäätmete hunnikus. Eriti palju oli koduste aiamaa jäätmete sees nt rabarberi lehtede vahel. Lisaks oli hunnikus porgandeid jt koduaia taimi.', to_timestamp(1690970406674/1000.0)),
