  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4595690430594, 24.8208849387271, true, 0, 'Arvukus: >_100. Need on kolm isendit Lillepi pargist ja neid võib leida praktiliselt kogu perimeetri ulatusest sadades...', to_timestamp(1721205712256/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3423458102592, 24.7885230212429, true, 0, 'Arvukus: 11_100. Terve kaardil märgitud tee on neid täis. Vajaksime kogumiskasti, sest eile leidsin esimesed kaks ka juba koduhoovist (Tohvri tänav, Luige). Terve meile tulev autotee on neid täis ja samas piirkonnas Hansaplanti poole minev kergliiklustee kubiseb nendest.', to_timestamp(1721220935790/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4541410327527, 24.3746130969614, true, 0, 'Arvukus: 11_100. Peale selle on veel Must-seatigu ka suures koguses.', to_timestamp(1721241455372/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.5391529180315, 24.8022000637532, true, 0, 'Arvukus: 11_100.', to_timestamp(1721245124040/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4538673946145, 24.8331345262417, true, 0, 'Arvukus: 11_100. Terve paekalda alune on täis ja edukalt paljuvad ka tänu niitmata murule', to_timestamp(1721245200625/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4275591519789, 24.6836410205269, true, 0, 'Arvukus: >_100. Kergliiklustee ääres Kõrgepinge tn on tigusid täiesti täis. Kõrgepinge ja Piibelehe ristumisele on paigutatud teetigude kogumise kast, millest ronivad teod välja. Kast haiseb.. Kraavid on niitmata ja tigusid lademes täis.', to_timestamp(1721288242018/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4321471124106, 24.3663246298052, true, 0, 'Arvukus: >_100. Sellel krundil olevalt metsast oleme korjanud 3 aasta jooksul ca 30 liitrit Lusitaania teotigusid. Kogu Vääna-Jõesuu kubiseb nendest!', to_timestamp(1721290857408/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4621310708575, 24.6686351576209, true, 0, 'Arvukus: 2_10.', to_timestamp(1721307822814/1000.0)),
