  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3784726836334, 24.312304258339, true, 0, 'Arvukus: 11_100. Keelva küla - Keila Joa tee äär on täis nälkjaid, üle saja kindlasti', to_timestamp(1721365785322/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4763289804832, 24.9664856288851, true, 0, 'Arvukus: >_100. Veehoidla tänava taga raudtee äärne ala, mis on omaniku hooldamata kubiseb sellest nälkjast, aedadesse tung samuti on selle aastaga suurenenud.Äkki on võimalik teha Raudtee omanikule kohustus teha ala niita ja puhastada võsast vähemalt regulaarselt', to_timestamp(1721373025544/1000.0)),
