  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4409433256174, 24.8040275562308, true, 0, 'Arvukus: 11_100. Teeteod on selles asukohas esimest aastat, varem olen märganud Kumu juures. Aedades veel pole näinud. Meie piirkonnas pole ka spestsiaalseid kogumiskaste. Olen teatanud ka Kadrioru parki ja Tallinna linna, kuid sealt pole vastust', to_timestamp(1721588412399/1000.0)),
