  (NULL, 'keskkonnaamet', 'arion_vulgaris', 56.9278901536998, 23.6932216709921, true, 0, 'Arvukus: >_100. The spanish slugs are overtaking the gardens and parks all over Latvia, they have no natural predators, so they keep breeding and multiplying, the government isn’t doing anything about this problem.', to_timestamp(1721645514473/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.9959456394561, 24.8138485924648, true, 0, 'Arvukus: >_100. Võsa ja Viljandi mnt vaheline garaazide ala', to_timestamp(1721658175347/1000.0)),
