  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3134912991003, 24.4174173433597, true, 0, 'Arvukus: >_100. Arvukus 1000-', to_timestamp(1721679342631/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3849305777598, 24.2533273640746, true, 0, 'Arvukus: 1. Piirkonnas on juba aasta aega teateid nendest tigudest aga oma krundil nägin esimest korda. Kahtlesin, kas on ikka võõrnäljas aga kõhualuse triibud nagu kohalikul liigil ei ole.', to_timestamp(1721728601470/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4895888131192, 24.9300703692911, true, 0, 'Arvukus: 11_100. Eelmisel aastal tulid juba siia :)', to_timestamp(1721747892515/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3773802886532, 24.5130758693009, true, 0, 'Arvukus: 2_10.', to_timestamp(1721758607727/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.368486799999, 24.2700934999996, true, 0, 'Arvukus: >_100. Juba ca 5 aastat on need siin külas levinud. Iga päev saab ca 100 tk neid ära korjatud, kui jääb päev või kaks vahele, siis on neid kohe ka palju rohkem. Nö "parimatel" päevadel oleme korjanud neid 1200 ruutmeetri pealt ca 250-300 tk.', to_timestamp(1721761153457/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4698055733875, 24.3710404340476, true, 0, 'Arvukus: >_100. Neid on meie territooriumil tuhandeid, eriti peale vihma.', to_timestamp(1721766904476/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3196679229474, 24.5514641909634, true, 0, 'Arvukus: 2_10.', to_timestamp(1721769930164/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3524201075585, 24.6339335544076, true, 0, 'Arvukus: 11_100. Hispaania teetigude rünnak Vanasilla 19 hoovile. Pesitsevad peamiselt Vanasilla 21 aias, mille hoov on hooldamata ja heina kasvanud. Ideaalne pesitsuspaik.', to_timestamp(1721821168400/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.358494290713, 26.6595741113013, true, 0, 'Arvukus: 11_100. väga palju oli neid ja suured. tee servas oli umbes 50 tk', to_timestamp(1721825281671/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 58.3380857417238, 25.5237119678203, true, 0, 'Arvukus: 1. U.10-15cm pikk', to_timestamp(1721828268023/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4802967286266, 24.935434902788, true, 0, 'Arvukus: >_100.', to_timestamp(1721837740259/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4407976295514, 24.5906834511974, true, 0, 'Arvukus: >_100.', to_timestamp(1721841955458/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.391169809428, 24.8564501260821, true, 0, 'Arvukus: 11_100.', to_timestamp(1721842453018/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.989990499999, 22.7471959999996, true, 0, 'Arvukus: >_100.', to_timestamp(1721906993834/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.5546429337441, 25.4360961913999, true, 0, 'Arvukus: >_100. Eile korjasin 8 liitrit. Naaber korjab igapäevaselt umbes 5kg per õhtu. Tulevad kuivenduskraavist ja kraaviüleselt looduskaitsealalt. On kiikunud ka üle tee valla omandis olevale mänguväljakule', to_timestamp(1721907674859/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4571475601122, 24.3742909902379, true, 0, 'Arvukus: >_100. Tee äärsed lagedad platsid kubisevad Hispaania teetigudest', to_timestamp(1721907852117/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.454850999999, 24.3745263999996, true, 0, 'Arvukus: >_100. Tuhandeid isendeid 50 ruutmetriselt alalt korjatud 20 minutiga umbes 2,5kg nälkjaid. Tulevad põhiliselt kuivenduskraavist ja ka looduskaitsealalt', to_timestamp(1721908325739/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4545686918005, 24.375164442468, true, 0, 'Arvukus: 11_100. Hispaania teod on ületanud vaikuse tee. Juba näha ka valla omandis oleval mängubäljakul. On vaja teha tõrjet..', to_timestamp(1721908850626/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4448154473033, 24.3783732555647, true, 0, 'Arvukus: >_100. Bussipeatuse ümbruses igal pool. Vajab hädasti tõrjet.', to_timestamp(1721909090916/1000.0)),
