  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.5546429337441, 25.4360961913999, true, 0, 'Arvukus: 11_100. Isendite arv on järsult tõusnud paari nädala jooksul alates juuli 2024 algusest. Kuna meie krundi vastas on mets, siis sealt nad meie aeda jõuavad. Kui võimalik võiks seal metsa all tõrjet teha.', to_timestamp(1721926635854/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3797787420128, 24.2500732883481, true, 0, 'Arvukus: >_100.', to_timestamp(1721931508085/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3812988197167, 24.2507386669488, true, 0, 'Arvukus: >_100. Naabrite palvel esitan ka nende kinnistuste märgistused.', to_timestamp(1721931711385/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3811898008183, 24.251225133968, true, 0, 'Arvukus: >_100. Esitan naabri palvel andmed.', to_timestamp(1721931877220/1000.0)),
