  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.101677999999, 25.5408672999996, true, 0, 'Arvukus: 11_100. Paar päeva tagasi korjasin kokku neid aianurgast kompostihunniku ümbrusest üle 20, täna veel 4 tükki.', to_timestamp(1722259506090/1000.0)),
