  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4949683032441, 24.852879273171, true, 0, 'Arvukus: >_100. Võrreldes eelmise aastaga on käesoleval aastal hispaania teetigu arvukus vähemalt kolmekordistunud. Teatele lisatud pildilt nähtub 5 minuti jooksul korjatud kogus.', to_timestamp(1722325744543/1000.0)),
