  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3603380823194, 26.7244183384285, true, 0, 'Arvukus: 11_100. Väga palju', to_timestamp(1722358941424/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.359248289237, 26.7249018380439, true, 0, 'Arvukus: >_100. Kergliiklustee ja selle äär on tigusid täis. Tapsin mitukümmend ära, aga neid on endiselt väga palju', to_timestamp(1722359379814/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3590051418106, 26.7260103612571, true, 0, 'Arvukus: 11_100. Eile leidsime ühe, täna juba 18', to_timestamp(1722360068310/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3593238137473, 26.7260486384509, true, 0, 'Arvukus: >_100. Viimased tund aega oleme korjanud. Üle saja juba leidnud. Tuleb järjest juurde kergliiklustee poolt ja suunaga aiamaale, maasikapeenrasse...', to_timestamp(1722362821286/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3959110121925, 24.7938137847672, true, 0, 'Arvukus: 11_100.', to_timestamp(1722362872716/1000.0)),
