  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3908370723302, 24.1947438614957, true, 0, 'Arvukus: 11_100. Siin on terve tee neid täis, ilmselt sadu, kui mitte tuhandeid', to_timestamp(1722363429468/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3128349379557, 24.5583494771722, true, 0, 'Arvukus: 11_100. Hispaania teeteod ilmesid meil see aasta, iga päevaselt korjame neid aias ca 5 -10 tk. Sarapiku tänaval neid on väga palju ja autod sõidavad peale. Pildid tehtud eilse õhtu jooksul. Naabritel sama seis!', to_timestamp(1722402664829/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4311579598163, 24.626623392317, true, 0, 'Arvukus: >_100.', to_timestamp(1722405663743/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4312484885711, 24.6261576770927, true, 0, 'Arvukus: 11_100.', to_timestamp(1722405977851/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4786932861028, 24.8568207849194, true, 0, 'Arvukus: 2_10.', to_timestamp(1722407795232/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.362593535037, 24.5224695953179, true, 0, 'Arvukus: >_100. Neid on palju ja eri suuruses. Mõned on pildil olevast suuremad ja jämedamad. Iga õhtu võimalik aiast korjata u 750g, aiast väljas tee peal ja äärtes veel rohkem.', to_timestamp(1722411847848/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3643126287288, 24.5248835547169, true, 0, 'Arvukus: >_100. Meeletult palju see aasta, eelmistel aastatel on ka juba olnud. Värvused tulevad tumepruunist oranžini. Suurused 3cm-10cmini isegi vist.', to_timestamp(1722414257692/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4297165210825, 28.0696677875418, true, 0, 'Arvukus: >_100.', to_timestamp(1722434028699/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.511834294566, 24.8431514848375, true, 0, 'Arvukus: >_100. Kogu Paeheina tee serv on täis', to_timestamp(1722448486692/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.5546429337441, 25.4360961913999, true, 0, 'Arvukus: >_100. Terve Suurupi upub nendesse.', to_timestamp(1722449787585/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3455692366823, 26.7096738187193, true, 0, 'Arvukus: >_100. Peale vihmasadu tänavad ja teeperved täis.', to_timestamp(1722449924613/1000.0)),
