  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3484517238152, 24.6310456222336, true, 0, 'Arvukus: 11_100. Появились года 3 назад, раньше ставили контейнер для из сбора недалеко от дома', to_timestamp(1722538015043/1000.0)),
