  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.4762098566961, 26.8892001724249, true, 0, 'Arvukus: 11_100. Iga päev korjan paarkümmrnd isendit.', to_timestamp(1722694999817/1000.0)),
