  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3545133500496, 24.6264607870576, true, 0, 'Arvukus: >_100. Vihmase ilmaga sai päeval kokku kogutud aiast ja ümbrusest >30 ja kui pimedaks läks siis sai teise ringiga ikka neid mõnusalt kinni püütud. Tegib lausa hasart, et palju veel saab... soola lahus ja prüginäpitsad aitavad hästi.', to_timestamp(1722714367500/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3182539582473, 24.4966427927041, true, 0, 'Arvukus: 11_100.', to_timestamp(1722722489391/1000.0)),
