  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.305347401834, 25.2811577341463, true, 0, 'Arvukus: >_100. selle kohal, teepeal esineb neid palju', to_timestamp(1722852369321/1000.0)),
