  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4362118393617, 24.3985422712324, true, 0, 'Arvukus: >_100.', to_timestamp(1722859818768/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.5227862248296, 24.8308850754201, true, 0, 'Arvukus: >_100.', to_timestamp(1722861706152/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4713097242733, 24.8955794190489, true, 0, 'Arvukus: 2_10. Metsatee mis kulgeb Põdrakanepiteega paralleelselt ning Laiaküla tee lõigul on peale vihma võimalik leida 1-10 isendit (punane joon). Metsa on kohalikud elanikud toonud aiaprügi, mis võib olla ka põhjuseks (sinine ring).', to_timestamp(1722861816068/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3561127250087, 26.7098199422196, true, 0, 'Arvukus: 2_10.', to_timestamp(1722877946350/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4579838765449, 24.6823824657597, true, 0, 'Arvukus: 11_100. aadressil Amburi 16 ja naaberhoovides', to_timestamp(1722882702853/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3621675420376, 26.691414530711, true, 0, 'Arvukus: >_100. Igal hommikul ja õhtul 20-30 tigu. Ja nii peaaegu iga päev. Naine lubas lahutuse anda kui kondamist ei lõpeta.', to_timestamp(1722882713285/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3631083515301, 24.6455635431435, true, 0, 'Arvukus: >_100. Nälkjad ronivad Pääsküla Jäätmekeskuse poolt', to_timestamp(1722886185024/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3631418791428, 24.6461408048152, true, 0, 'Arvukus: >_100. Nälkjad ronivad Pääsküla Jäätmekeskuse poolt', to_timestamp(1722886331894/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3719335102258, 24.2524556035797, true, 0, 'Arvukus: >_100. Märkasin aiamaal Hispaania teetigu juulis 2024, mustpeanälkjat näinud ka varem. Eelmistel aastatel on aia niiskemates kohtades leidunud kohalik seatigu, nüüd neid vaid mõned üksikud.', to_timestamp(1722893362859/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3599242194615, 26.7233590581605, true, 0, 'Arvukus: >_100.', to_timestamp(1722917563703/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4819880879866, 24.848742971592, true, 0, 'Arvukus: >_100.', to_timestamp(1722949074737/1000.0)),
