  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.536705487192, 24.8076827939636, true, 0, 'Arvukus: >_100.', to_timestamp(1722964899643/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.5546429337441, 25.4360961913999, true, 0, 'Arvukus: 11_100.', to_timestamp(1722970298540/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.2598941699379, 22.5256769534263, true, 0, 'Arvukus: >_100. Isendeid oli palju terviserajal.', to_timestamp(1722971747276/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4509311642458, 24.6915576163448, true, 0, 'Arvukus: 11_100. Märgitud kohas oli hästi pikk muru olnud suhteliselt kaua, sai neetud, tuli välja palju elukaid', to_timestamp(1722973174068/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4761340588156, 24.9350131802619, true, 0, 'Arvukus: >_100.', to_timestamp(1722976989588/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3173194394062, 24.5642674642449, true, 0, 'Arvukus: 11_100. 5 suurt ja sadu pisikesi', to_timestamp(1722981236419/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4891040017463, 24.8859436180846, true, 0, 'Arvukus: 11_100.', to_timestamp(1723009317569/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3426122282776, 26.7842064458034, true, 0, 'Arvukus: >_100. Rannapuiestee tn kraavis väga palju isendeid, sealt rädavad aedadesse. Aiast korjatud sel aastal üle 500 isendi.', to_timestamp(1723020586785/1000.0));
INSERT INTO public.observations (user_id, source, species, lat, lng, present, killed_count, note, observed_at) VALUES
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.5546429337441, 25.4360961913999, true, 0, 'Arvukus: 2_10. Paar päeva tagasi teatasin ka. Tõenäoliselt on piirkonnas nende leviku soodustamiseks sobiv kinnistu Ööbiku 2, kus nö tagaaias teatud ulatuslikke piirkondi ei niideta üldse. Samuti on läheduses raudteeäärne ala, mille korrashoiuga linn tegeleb harva..', to_timestamp(1723023163252/1000.0)),
