  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.9252316170847, 24.7229575831378, true, 0, 'Arvukus: 11_100. Metsas jalutades peale vihma on neid väga palju metsa all ning ühtlasi tee peal ja koguseliselt on neid seal palju. Osad on väga suured.', to_timestamp(1723190106356/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4365894792215, 24.699416535467, true, 0, 'Arvukus: 2_10. Seen on Saturday 3 August', to_timestamp(1723190822086/1000.0)),
