  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.2601141646949, 22.5255112541015, true, 0, 'Arvukus: 11_100. Pilti sel korral ei teinud, aga neid tigusid on seal igal sammul. Lihtsalt kohutav.', to_timestamp(1723198834540/1000.0)),
