  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.2693671333926, 24.5879841430988, true, 0, 'Arvukus: 2_10. Pole varem olnud neid minu hoovis, nüüd paari päevaga juba 9 tk kompostihunnikus ja selle läheduses.', to_timestamp(1723290987646/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.2844762573355, 24.6420661866166, true, 0, 'Arvukus: >_100. Levik massiline', to_timestamp(1723313499200/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.272011999999, 23.8735953999996, true, 0, 'Arvukus: >_100.', to_timestamp(1723323138289/1000.0)),
