  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3269905744998, 24.4729778386438, true, 0, 'Arvukus: 11_100. Iga päev korjan u 20 hispaania teetigu Jaarli teelt ja Tutermaa teelt teeservadest. Pildil nii Hispaania teetigu kui mustpeanälkjas.', to_timestamp(1723359754080/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4578352196184, 24.8364769306995, true, 0, 'Arvukus: 11_100. Palju ja pidevalt', to_timestamp(1723366805202/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4600068628608, 24.8241132520256, true, 0, 'Arvukus: 11_100. Suurem pesa, kõrval oli samuti selline suurem hunnik neid koos.', to_timestamp(1723366999037/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4581641220898, 24.8273211740073, true, 0, 'Arvukus: 11_100. Neid oli seal rohkem.', to_timestamp(1723367109412/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4596126310943, 24.8368912957727, true, 0, 'Arvukus: 11_100. Ümbruses oli neid veel, terve suur pesakond. Sai ära korjatud.', to_timestamp(1723367217227/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3700553763165, 26.7985275947679, true, 0, 'Arvukus: 1.', to_timestamp(1723379189809/1000.0)),
