  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.5546429337441, 25.4360961913999, true, 0, 'Arvukus: 11_100. Isendeid oli palju ning kindlasti oli rohtu kasvanud jõeäärsel alal veelgi.', to_timestamp(1723403457652/1000.0)),
