  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3803662883026, 26.746759063912, true, 0, 'Arvukus: >_100. Kahjuks häid pilte ei ole, sest korjame vihmase ilmaga. Krundil on esinenud kaks Eesti liiki ka varem ( must triibuline ja hele). See kevad märkasime ka hispaania oma ja suve lõpus on arvukus eksponentsiaalselt kasvanud.', to_timestamp(1723489359160/1000.0)),
