  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3803764882243, 24.2459086162252, true, 0, 'Arvukus: 11_100. Neid on tuhandeid :(', to_timestamp(1751927483653/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3163252618706, 24.5298326781624, true, 0, 'Arvukus: 11_100.', to_timestamp(1751953465063/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3666430089213, 25.1751119804053, true, 0, 'Arvukus: 11_100. Vihmase ilmaga roomas ca 30 suurt ja väiksemat hispaania teetigu kergliiklusteel suunaga sõidutee poole', to_timestamp(1751964053862/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4346757699533, 24.7994767431168, true, 0, 'Arvukus: 11_100.', to_timestamp(1751965314018/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3856130071849, 24.239235112555, true, 0, 'Arvukus: >_100. Появились около 5ти лет назад. На данный момент 8.7.2025 заражена ими вся округа. Собираю каждый день более 100 штук', to_timestamp(1751965918745/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4348664426487, 24.7911371781256, true, 0, 'Arvukus: 2_10.', to_timestamp(1751966549459/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4354264100847, 24.7890381404846, true, 0, 'Arvukus: 2_10.', to_timestamp(1751967086507/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.1284222740001, 25.204250985, true, 0, 'Arvukus: 2_10.', to_timestamp(1751968590574/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.1633869344317, 24.7523698147267, true, 0, 'Arvukus: 11_100.', to_timestamp(1751971438818/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4921686794137, 24.8990013659462, true, 0, 'Arvukus: 11_100.', to_timestamp(1751980445424/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4222473411369, 24.6491296077137, true, 0, 'Arvukus: 11_100. Neid on siin väga palju, peale vaadates pakuks, et vähemalt 50.', to_timestamp(1751981612512/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3545279319545, 26.3716637008406, true, 0, 'Arvukus: >_100. Vihmase ilmaga on 15 minutiga võimalik leida sellise hunniku isendeid, nagu pildil. Põhimõtteliselt leiab ühe iga 20 cm tagant. See aasta, 2025, on neid ikka hullult palju. Eelmistel aastatel olid üksikud. Nüüd on küll mõned taimed rootsudeks söödud.', to_timestamp(1751984133996/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3506206095756, 24.0797074214874, true, 0, 'Arvukus: >_100.', to_timestamp(1751988458389/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3400399576344, 24.3873058492948, true, 0, 'Arvukus: >_100.', to_timestamp(1751996108736/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.5546429337441, 25.4360961913999, true, 0, 'Arvukus: >_100.', to_timestamp(1751997474765/1000.0));
INSERT INTO public.observations (user_id, source, species, lat, lng, present, killed_count, note, observed_at) VALUES
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4409845653055, 24.8165745588504, true, 0, 'Arvukus: >_100. Kogu ümbrus ja tee umbes 200 meetri ulatuses on kaetud suure hulga Hispaania teetigudega.', to_timestamp(1751998969989/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.802571899999, 22.7273374999996, true, 0, 'Arvukus: 2_10.', to_timestamp(1751999202122/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3890834855504, 24.634983402041, true, 0, 'Arvukus: >_100. Niiske metsaalune: naatide, vereurmarohu ja kassitapu taimed on paksult isendeid täis, nii teetigusid kui mustpeanälkjaid.', to_timestamp(1751999986455/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.2037973735499, 24.639031945094, true, 0, 'Arvukus: >_100.', to_timestamp(1752000389949/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.2037684978935, 24.6383634883158, true, 0, 'Arvukus: >_100. Terve variku ja juure põik tänav on neid täis.', to_timestamp(1752000545388/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.383246199999, 24.8467962999996, true, 0, 'Arvukus: 2_10.', to_timestamp(1752001430950/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.9574394218702, 22.780462754298, true, 0, 'Arvukus: 2_10.', to_timestamp(1752007448283/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.0990429813577, 23.9735756855612, true, 0, 'Arvukus: 11_100.', to_timestamp(1752048421363/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3892019040489, 24.560644352443, true, 0, 'Arvukus: >_100. Terve tee kuni harku terviserajani ja ka kergliiklustee paldiski mnt ääres. Sadu isendeid on näha.', to_timestamp(1752049959769/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3900452704161, 24.6660006694135, true, 0, 'Arvukus: 2_10. Hispaania teetigu', to_timestamp(1752056121541/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.2311400531293, 24.7333017851847, true, 0, 'Arvukus: >_100.', to_timestamp(1752061441597/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.0644282223123, 24.8034628876668, true, 0, 'Arvukus: >_100.', to_timestamp(1752061462555/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4052970453581, 24.943054041809, true, 0, 'Arvukus: >_100.', to_timestamp(1752072292095/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4617958518298, 24.4116147718213, true, 0, 'Arvukus: >_100.', to_timestamp(1752074499520/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4721121253685, 24.944484087147, true, 0, 'Arvukus: 11_100.', to_timestamp(1752079656304/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4023342334676, 24.943570794977, true, 0, 'Arvukus: >_100.', to_timestamp(1752084580412/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3290822114493, 24.8083373253098, true, 0, 'Arvukus: 2_10.', to_timestamp(1752086036704/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4744717726252, 26.7803598582081, true, 0, 'Arvukus: 1.', to_timestamp(1752088808987/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.354206834423, 25.5641399849794, true, 0, 'Arvukus: >_100.', to_timestamp(1752090428437/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.328208691639, 24.7779159701406, true, 0, 'Arvukus: 1. Leid on kindel. Ookerkollane oranžikas, õhuavaga pea küljel. Pilti ei teinud, sest polnud aimugi, et seda vaja peaks olema.', to_timestamp(1752090873978/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.5546429337441, 25.4360961913999, true, 0, 'Arvukus: 11_100.', to_timestamp(1752091873056/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.208260029481, 24.3380030155343, true, 0, 'Arvukus: >_100.', to_timestamp(1752091981923/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3900866547711, 24.7987571846346, true, 0, 'Arvukus: >_100. Levivad laohoone haljasala olematu hoolduse tõttu igasse ümbruskonna aeda. Talvituvad tõenäoliselt eriti edukalt talveks maha jääva kulu all.', to_timestamp(1752106231871/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3905720865888, 24.7975046438544, true, 0, 'Arvukus: >_100. Kaare tee 7 kinnistut ei niideta, mistõttu levib sealt massiliselt kõrvalkruntidele Hispaania teetigusid. Tegu on ideaalse talvitumiskohaga, sest lume alla jääb paks kulukiht', to_timestamp(1752106457571/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.118266998055, 24.3100250057679, true, 0, 'Arvukus: >_100. Iga õhtu korajame u 400 tk juba u kuu aega', to_timestamp(1752126236845/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3978522375216, 26.7311773573659, true, 0, 'Arvukus: 11_100.', to_timestamp(1752127858644/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.6309778790001, 25.557831821, true, 0, 'Arvukus: 11_100.', to_timestamp(1752129847379/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.31389274975, 24.6620293728365, true, 0, 'Arvukus: >_100. oleme see aasta korjanud neid kilode ja kilode kaupa (10+ vähemalt). pildid on 15L ämber kus on nälkijad soolvees', to_timestamp(1752134410914/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3917801256903, 24.8572623689226, true, 0, 'Arvukus: >_100.', to_timestamp(1752137584691/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.1644685500374, 24.748588702759, true, 0, 'Arvukus: >_100. Tigusid on metsa servas massiliselt', to_timestamp(1752139262381/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.1630539256395, 24.749864750014, true, 0, 'Arvukus: >_100. Keegi on viinud oma aiajäätmed metsa ja ehk koos nendega ka teod', to_timestamp(1752139404359/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.2362859720299, 25.7843482036636, true, 0, 'Arvukus: 1.', to_timestamp(1752149497815/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4359428161419, 24.7001990374449, true, 0, 'Arvukus: >_100. Palun võtke midagi ette. Olen korjanud 11 päeva jooksul õhtuti jalutades kokku 3108 Hispaania teetigu. Mitte ühelgi aastal ei oke neil väikestel teelõikudel neid tigusid kohanud kuigi tean, et läheduses teedel on neid varasemalt nähtud. See on meeletu.', to_timestamp(1752150833807/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.2346939659839, 26.8149668848212, true, 0, 'Arvukus: >_100. Neid on siinkandis ikka sadades- tuhandetes.', to_timestamp(1752159481107/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 57.8487717661961, 27.0147832053602, true, 0, 'Arvukus: >_100.', to_timestamp(1752160375415/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4581610872905, 28.0468261021351, true, 0, 'Arvukus: >_100.', to_timestamp(1752164836123/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4304839580476, 24.7993313728473, true, 0, 'Arvukus: 11_100. Praegu vihmaga olid väiksemad kui eile. Eelneval päeval olid suured ja arvukamalt. Ilmselt on neid rohkem kui 100, aga ma ei tea, kui suurt piirkonda ma pean arvesse võtma. Konkreetsel lühikesel teelõigul oli üle 10.', to_timestamp(1752165175587/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3564321423624, 26.7670265708746, true, 0, 'Arvukus: 1.', to_timestamp(1752165628315/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.9990833226996, 22.7350075429444, true, 0, 'Arvukus: 11_100.', to_timestamp(1752167931856/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.361439933703, 27.4298829992441, true, 0, 'Arvukus: 11_100.', to_timestamp(1752169360623/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3565656362213, 26.7664170623328, true, 0, 'Arvukus: 2_10. Ilmselt arvukus suurem, tulevad põllu pealt (lähedal kraav).', to_timestamp(1752169695523/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.1008301868625, 27.4706365857414, true, 0, 'Arvukus: >_100.', to_timestamp(1752171198649/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3671198919403, 25.1740143599933, true, 0, 'Arvukus: 11_100.', to_timestamp(1752171927736/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.5546429337441, 25.4360961913999, true, 0, 'Arvukus: >_100.', to_timestamp(1752175174508/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.0018247064327, 24.7858318223557, true, 0, 'Arvukus: 11_100.', to_timestamp(1752175525187/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4362203820777, 24.3767492866035, true, 0, 'Arvukus: >_100.', to_timestamp(1752175683753/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.0019398789416, 24.7840465077537, true, 0, 'Arvukus: 1.', to_timestamp(1752175777204/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.0038736910954, 24.7902573997201, true, 0, 'Arvukus: 2_10.', to_timestamp(1752176100640/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3759287241969, 24.9481086424412, true, 0, 'Arvukus: >_100.', to_timestamp(1752176847041/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3613162958475, 26.6539665070257, true, 0, 'Arvukus: 11_100.', to_timestamp(1752180382788/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.2641341297386, 24.0641742045132, true, 0, 'Arvukus: 11_100.', to_timestamp(1752182790411/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3449894143835, 25.3362035040109, true, 0, 'Arvukus: 11_100.', to_timestamp(1752218137780/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4561912698448, 24.6888678760912, true, 0, 'Arvukus: 11_100. There are plenty of them on Maleva bus stop and a pavement towards the Kopli. I counted at least 30, but there are a lot every day.', to_timestamp(1752220872976/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3838186336196, 24.8451948165832, true, 0, 'Arvukus: 11_100.', to_timestamp(1752221504300/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3998247849357, 24.2906699870489, true, 0, 'Arvukus: >_100. Очень много повсеместно в парке Кейла Йоа, в лесу, на дорогах.', to_timestamp(1752221905018/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4694503953073, 24.9392184917532, true, 0, 'Arvukus: >_100. neid on tohutult palju, kõiki on võimatu koguda, kuigi kõik naabrid koguvad neid pidevalt', to_timestamp(1752223046122/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4352511651391, 24.7524099168438, true, 0, 'Arvukus: 1. Üks 4 cm tegelane oli teepeal', to_timestamp(1752225909063/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4614237446369, 24.8699548574071, true, 0, 'Arvukus: 2_10.', to_timestamp(1752228921402/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.5205791741435, 25.2704403398522, true, 0, 'Arvukus: >_100.', to_timestamp(1752229712776/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4263299877878, 24.7907765790777, true, 0, 'Arvukus: 11_100.', to_timestamp(1752231389821/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.2062217116344, 24.3381054440233, true, 0, 'Arvukus: >_100. Это какой-то ужас! Их очень много. Боремся разными методами: собираем в банку с солью, сыпем соль на них на земле, обрызгиваем из уксусом из пульверизатора', to_timestamp(1752233784851/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.4154835405822, 26.7636944003655, true, 0, 'Arvukus: 1.', to_timestamp(1752238288447/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4324284193054, 24.4007686327377, true, 0, 'Arvukus: >_100.', to_timestamp(1752238539225/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3685089148549, 28.1615082058183, true, 0, 'Arvukus: >_100.', to_timestamp(1752245248589/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.0066982830081, 24.784824066221, true, 0, 'Arvukus: >_100.', to_timestamp(1752245566903/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3703487442668, 28.1690267977161, true, 0, 'Arvukus: >_100. Palun abi', to_timestamp(1752246395427/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4108222284901, 24.6020176750654, true, 0, 'Arvukus: 11_100. весь огородний участок ими заполнен', to_timestamp(1752249250745/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3957868648296, 27.7831360034111, true, 0, 'Arvukus: >_100.', to_timestamp(1752252547802/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3172462564435, 24.522381212102, true, 0, 'Arvukus: >_100.', to_timestamp(1752253231491/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.2215749710899, 24.6807256269645, true, 0, 'Arvukus: >_100.', to_timestamp(1752257580941/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3471424703043, 24.9167879598661, true, 0, 'Arvukus: 11_100.', to_timestamp(1752258499799/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3898950694892, 24.3269968940096, true, 0, 'Arvukus: 11_100. Oleme olnud suvilas nüüd 4 päeva ja igal õhtul avastanud kuni 7 hispaanlast.', to_timestamp(1752267405270/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4545170564996, 28.0329942385647, true, 0, 'Arvukus: >_100. Огромное количество испанских и черноголовых слизней!!! Просто катастрофа!!', to_timestamp(1752268582882/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.425062045923, 24.6300913275014, true, 0, 'Arvukus: 11_100. Sama pikad ja jämedad kui taskurätipakk. Perspektiiv ei ole pildil hästi paigas.', to_timestamp(1752268611219/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 58.3813909619322, 26.6986813954532, true, 0, 'Arvukus: 2_10.', to_timestamp(1752269044004/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3863548475254, 24.8598039824794, true, 0, 'Arvukus: 11_100.', to_timestamp(1752293704439/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.1143968271057, 25.554195639009, true, 0, 'Arvukus: >_100.', to_timestamp(1752296099099/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3625931891576, 27.3981517509168, true, 0, 'Arvukus: 11_100.', to_timestamp(1752300122544/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.4180035902677, 26.7571523293357, true, 0, 'Arvukus: 2_10.', to_timestamp(1752303951686/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4768003209333, 25.0409377565525, true, 0, 'Arvukus: >_100.', to_timestamp(1752309701784/1000.0)),
