  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.360088003766, 25.5971583197912, true, 0, 'Arvukus: 2_10. Hispaania teetigusid on täis kõik kolm Kirsimäge. Hõlpsalt leitavad lossimüüridedel vallikraavi poolselt küljelt, kus pole niidtud ning on piisavat niiskust. Eriti kohad, kust on kivid välja kukkunud, nagu näha esimeselt ülevaatlikumalt pildilt.', to_timestamp(1752402076049/1000.0)),
