  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3517773984495, 26.7119332672079, true, 0, 'Arvukus: 11_100. 23. aprillil kella 21 paiku tehtud foto raudtee ülesõidul. Alal liikus neid väga palju – neid leidus kogu tee ulatuses ja ka muruäärsetel aladel. Hinnanguliselt umbes 30+ tegelast. Haisesid meeletult, võimatu mitte märgata.', to_timestamp(1753221692344/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.5188252976241, 24.8244764994618, true, 0, 'Arvukus: 1.', to_timestamp(1753248055081/1000.0)),
