  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.0471763514701, 26.474502695014, true, 0, 'Arvukus: >_100. väga palju,korjame 2-3 korda päevas,põhiliselt oma kinnistu piirilt (piirneb nelja naaberkinnistuga)', to_timestamp(1753257972834/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 57.8853050190421, 26.994240287223, true, 0, 'Arvukus: 11_100.', to_timestamp(1753264346017/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.2457374844966, 22.4960738628522, true, 0, 'Arvukus: >_100. Igal ohtul olenevalt ilmast korjan 50-200 isendit. Kõige suurem vihmase ilmaga õhtul oli 286 kui alustasin korjamisega.', to_timestamp(1753266240952/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3374160234326, 27.2945674046521, true, 0, 'Arvukus: 11_100.', to_timestamp(1753267262464/1000.0)),
