  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3708392322859, 28.1729248856068, true, 0, 'Arvukus: >_100. Neid tuleb järjest juurde, vihmase ilmaga korjame umbes 500–700 tükki.', to_timestamp(1753272905174/1000.0)),
