  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3335190575559, 24.7740114543817, true, 0, 'Arvukus: 1.', to_timestamp(1753336525751/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3850383962516, 21.889418464793, true, 0, 'Arvukus: 11_100.', to_timestamp(1753337961725/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 58.5546429337441, 25.4360961913999, true, 0, 'Arvukus: >_100. Tere! Palun tagasisidet, kas tegu võib olla Hispaania teeteo vastkoorunud poegadega? Tulevad välja öösel ja neid on sadu. Naabri aias on ka mõni üksik hispaania tigu, kes vastab ülaltoodud kirjeldusele. Pildistatud isenditel on samasugused vöödid kehal.', to_timestamp(1753339276267/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3682960325389, 24.8238255702575, true, 0, 'Arvukus: 2_10.', to_timestamp(1753339288544/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3702095637948, 24.544087218309, true, 0, 'Arvukus: 11_100. Они выходят на дорогу когда идет дождь', to_timestamp(1753373586954/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.5546429337441, 25.4360961913999, true, 0, 'Arvukus: >_100.', to_timestamp(1753380158988/1000.0)),
