  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.5546429337441, 25.4360961913999, true, 0, 'Arvukus: >_100. No neid on tuhandeid sellel aastal ja siin piirkonnas paraku ka esimene kord.', to_timestamp(1753392520497/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.63939594046, 25.5132913522361, true, 0, 'Arvukus: 2_10. Nägin 7 Hispaania tigu tee peal', to_timestamp(1753414783847/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.0032868268915, 24.7942845731947, true, 0, 'Arvukus: >_100. Korjan keskmiselt 50 tigu päevas', to_timestamp(1753421098238/1000.0)),
