  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.1866207936226, 24.3532343869083, true, 0, 'Arvukus: 11_100.', to_timestamp(1753426519413/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.3690692416826, 25.3094318117986, true, 0, 'Arvukus: 2_10. Ei ole kindel kas oma- või võõrliiki nälkjas/teetigu', to_timestamp(1753433601175/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.2675784997982, 24.8592473402895, true, 0, 'Arvukus: >_100.', to_timestamp(1753458818985/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4544256999844, 24.5754114567426, true, 0, 'Arvukus: 2_10. Palun infot, mis liigiga on tegemist ja kas neid tuleks hävitada.', to_timestamp(1753477754290/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.5546429337441, 25.4360961913999, true, 0, 'Arvukus: 11_100. Наблюдали за слизнями на территории Nõmme Spordikeskus в вечернее время. Количество их было гораздо больше чем 20. Длиной особи были как 5см так и 12см. Сообщили работникам парка.', to_timestamp(1753523239937/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3607308744174, 25.599087026057, true, 0, 'Arvukus: 1.', to_timestamp(1753550598616/1000.0)),
