  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3922156216112, 24.8176093207947, true, 0, 'Arvukus: >_100. Palju teetigusid erinevates suurustes - Algus ennem ringristmikku muru sees valge aiaga ridaelamust kuni jäätmepunktist poole põlluteeni - ilmselt ka mujal sealkandis', to_timestamp(1753557522984/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3665535651923, 24.2574331463582, true, 0, 'Arvukus: 11_100.', to_timestamp(1753562929743/1000.0)),
