  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3631031628398, 27.4449687264082, true, 0, 'Arvukus: >_100. Имеются все виды слизней в огромном количестве,собираем ведрами', to_timestamp(1753597824670/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4574706910001, 24.9109726880001, true, 0, 'Arvukus: 11_100. Tigusi on rohkelt ja massiliselt nii Iru kûla aedades, teedel kui ka Iru looduskaitsealal jõe ûmbruses.', to_timestamp(1753609460885/1000.0)),
