  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4868610331262, 24.8536563594144, true, 0, 'Arvukus: >_100. Pildid on erinevatest aastatest.', to_timestamp(1753769193861/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4868610331262, 24.8536563594144, true, 0, 'Arvukus: >_100. Need peaksid olema meie kohalikud, mitte võõrliigid, aga kahju on neist rohkem. Söövad taimi (maasikaid, kurgitaimi jne), üks ronis sisse värava automaatika seadmesse, tekitas lühise, automaatika komponendid põlesid läbi ja nõudsid välja vahetamist.', to_timestamp(1753769726090/1000.0)),
