  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3657867048708, 27.3968051594667, true, 0, 'Arvukus: >_100. See juba korjatud. Korjame iga päev hommikul ja õhtul.', to_timestamp(1753775367315/1000.0)),
