  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3429489692038, 26.7872808681345, true, 0, 'Arvukus: >_100. Korjamine iga öö Ranna pst 12, 14, 16 ja 18 krundilt ja aia tagant kraavi alalt', to_timestamp(1753794615096/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.304607299999, 24.4016532999996, true, 0, 'Arvukus: >_100.', to_timestamp(1753797883288/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.5546429337441, 25.4360961913999, true, 0, 'Arvukus: 1. Ma ei ole päris kindel, kas tegu on ikka hispaania pahalasega.', to_timestamp(1753808633085/1000.0)),
