  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3452892933615, 24.8071768907249, true, 0, 'Arvukus: >_100. suur kolle kangru teel vaelas kiili vald, palun survestada valda teha tǒrjet avalikel teedel', to_timestamp(1754725889785/1000.0)),
