  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3661224080948, 26.762418555679, true, 0, 'Arvukus: 2_10.', to_timestamp(1754732253221/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.22194, 22.34056, true, 0, 'Arvukus: 2_10.', to_timestamp(1754740638224/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.22068, 22.33696, true, 0, 'Arvukus: 2_10. Terve tee isendeid täis.', to_timestamp(1754740705191/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.21922, 22.33674, true, 0, 'Arvukus: 2_10.', to_timestamp(1754740795803/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.44345304509, 24.7328517173056, true, 0, 'Arvukus: 1. Hispaania teetigu', to_timestamp(1754749366457/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.386785703434, 24.8527109488497, true, 0, 'Arvukus: >_100. Tee äär, Raeküla tee kraavi pool kuni peatuseni täis. Nähtud õhtul ja hommikul ka suured isendid. Kasutame IronMax Pro + õlu lõksud. Korjata ei jõua.', to_timestamp(1754754343977/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.389136199999, 24.6706287999996, true, 0, 'Arvukus: 11_100.', to_timestamp(1754763500697/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3889572242274, 24.9518574153018, true, 0, 'Arvukus: 11_100.', to_timestamp(1754768477196/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.443591842428, 24.8393172691841, true, 0, 'Arvukus: 11_100.', to_timestamp(1754768624363/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.7526346457901, 26.4000376995653, true, 0, 'Arvukus: 11_100.', to_timestamp(1754769546518/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3702680717238, 24.5292599788964, true, 0, 'Arvukus: 1.', to_timestamp(1754774766218/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.5546429337441, 25.4360961913999, true, 0, 'Arvukus: >_100. Teod Haljala alevikus, Haljala teeristis, Maardus Sibula teel.', to_timestamp(1754778620132/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4465413419279, 25.1223203443097, true, 0, 'Arvukus: 11_100.', to_timestamp(1754807544036/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.4102795824456, 24.494226018197, true, 0, 'Arvukus: >_100. Ise elan naaberkinnistul ja tapan tigusid igapäevaselt (õigemini öösiti) 50-100tk', to_timestamp(1754824749920/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 58.4102795824456, 24.494226018197, true, 0, 'Arvukus: >_100. Teie rakendus on veidi segane. Nimetatud kinnistul on nii hispaanlasi kui ka suuri seatigusid. Kas nüüd õnnestus mõlemad esitada??', to_timestamp(1754825186197/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.49177589935, 24.8689873713338, true, 0, 'Arvukus: >_100.', to_timestamp(1754825207294/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3590855417559, 25.5950898363898, true, 0, 'Arvukus: >_100.', to_timestamp(1754825306230/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4916788719725, 24.8681353101704, true, 0, 'Arvukus: >_100.', to_timestamp(1754825556459/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3829380238349, 24.5168760998719, true, 0, 'Arvukus: >_100. Tigude levik on kindlasti kinnistutel Riia mnt 29-41, Pärnu linnas. Ehk Suur-Posti ja Laatsareti tänavate vahel', to_timestamp(1754825643580/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4915868490985, 24.8686174186397, true, 0, 'Arvukus: >_100.', to_timestamp(1754825656703/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4946627948116, 24.8753031899244, true, 0, 'Arvukus: >_100.', to_timestamp(1754825766817/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.9321931394904, 23.5216254103544, true, 0, 'Arvukus: 2_10.', to_timestamp(1754830502748/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3661176859019, 25.0673710645624, true, 0, 'Arvukus: 1.', to_timestamp(1754831816802/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.5255355494989, 24.8092976613784, true, 0, 'Arvukus: >_100.', to_timestamp(1754836439908/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3546592334209, 26.700827502231, true, 0, 'Arvukus: 2_10.', to_timestamp(1754842038295/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.365526276778, 24.9232269443883, true, 0, 'Arvukus: >_100.', to_timestamp(1754844079248/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4028416758427, 24.2815049358115, true, 0, 'Arvukus: 11_100. Eelkõige jõeäärsetes majapidamistes.2024a olid harva mõned üksikud isendid.', to_timestamp(1754844934029/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3691823008259, 24.2687579209014, true, 0, 'Arvukus: >_100.', to_timestamp(1754849288437/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.9631890829536, 24.8311990499427, true, 0, 'Arvukus: 2_10.', to_timestamp(1754849480501/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.389468846797, 25.8076531821531, true, 0, 'Arvukus: 11_100.', to_timestamp(1754858360538/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.5028375068393, 24.8154726276563, true, 0, 'Arvukus: 11_100. eero hammer', to_timestamp(1754891856739/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.1862996877381, 24.3666668431607, true, 0, 'Arvukus: 11_100.', to_timestamp(1754893985859/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4968562807584, 24.8260465264258, true, 0, 'Arvukus: 2_10. Vahe tee 3/Kalda tee 10 ja 8 hoovide ristumiskohas avastasin nädal tagasi ca 4-5 tükki, hävitasin, puhastasin aia ning olen sellest alates igal õhtul 1-2 tükki kokku korjanud ning hävitanud. Kuna naabritel kalda tee 8 ja 10 majadel on seal aianurgas sodi', to_timestamp(1754894201448/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4971495674472, 24.8265010937748, true, 0, 'Arvukus: 2_10. Kalda tee 6 aia tagant, Vahe tee poolt olen korjanud 2-3 tükki nädala jooksul. Samamoodi on seal kalda 6 aed täielik rämps.', to_timestamp(1754894284704/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.5546429337441, 25.4360961913999, true, 0, 'Arvukus: >_100. tõelised nuhtlused, iga õhtu korjan ca 3 kg', to_timestamp(1754895828969/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3585003755793, 26.728949866597, true, 0, 'Arvukus: >_100. Iga õhtu/hommik korjan ca 3 kg', to_timestamp(1754895939334/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.2481515939858, 22.4882786042233, true, 0, 'Arvukus: 11_100.', to_timestamp(1754896012065/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.422623703013, 27.5126967449425, true, 0, 'Arvukus: >_100.', to_timestamp(1754900824623/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.5043018457965, 24.9043400515357, true, 0, 'Arvukus: >_100.', to_timestamp(1754908430416/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 58.652757399999, 25.0378528999996, true, 0, 'Arvukus: 11_100. Suur-seatigu - leidsime neid 13 tk, 3 suurt ja teised väikesed u 1-2cm pikkused. Must-seatigu oli 1 puuriidas.', to_timestamp(1754917074844/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3445092620238, 22.4490284158609, true, 0, 'Arvukus: >_100. Iga õhtuga järjest rohkem.', to_timestamp(1754937710092/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.2255449720001, 26.418598526, true, 0, 'Arvukus: 11_100. Liigub ka aiaga pikki lubjakivi.', to_timestamp(1754944384416/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4197918328778, 24.6952227156101, true, 0, 'Arvukus: >_100.', to_timestamp(1754994056591/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.498008509685, 25.459043662689, true, 0, 'Arvukus: 2_10. Teen uued fotod, kui jälle näen', to_timestamp(1755005541416/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.357431794495, 26.6833044092789, true, 0, 'Arvukus: >_100.', to_timestamp(1755020023095/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.9967113465946, 24.8168863070944, true, 0, 'Arvukus: 11_100.', to_timestamp(1755021356607/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.9974665103779, 24.8213282212122, true, 0, 'Arvukus: 11_100.', to_timestamp(1755024144640/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.9978411319793, 24.8211446837587, true, 0, 'Arvukus: 11_100. Arvukus selles piirkonnas tõuseb', to_timestamp(1755024231106/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.9980593731562, 24.8205492480847, true, 0, 'Arvukus: 2_10. Ala kust tigusid leiab, laieneb. Leidub juba metsavahelt väljuvalt teerajalt. Midagi peaks ette võtma, et piirata nende levikut. Ainult korjamine mõne kogukonnaliikme poolt ei anna suurt efekti.', to_timestamp(1755024420444/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.6610781647064, 25.9835816624431, true, 0, 'Arvukus: >_100.', to_timestamp(1755062738860/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3580642911907, 26.7286270861206, true, 0, 'Arvukus: 11_100.', to_timestamp(1755063074986/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3723519629555, 26.8098779023275, true, 0, 'Arvukus: 2_10. Eile oli samal kõnniteel neid palju rohkem', to_timestamp(1755104091345/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.5106831982316, 24.8436513425986, true, 0, 'Arvukus: >_100.', to_timestamp(1755105823986/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.2271886141003, 24.6757465106454, true, 0, 'Arvukus: >_100. Bussijaama kõrval rohealal/kraavi serval neid väga palju. Ennem hommikust bussi jõudsime 8min neid 27tk soolvette korjata.', to_timestamp(1755148687230/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3594860060108, 25.0825264709474, true, 0, 'Arvukus: 1. Keegi oli soolaga üle kallanud juba.', to_timestamp(1755149841967/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.6610207571841, 25.9673642977004, true, 0, 'Arvukus: >_100.', to_timestamp(1755151900550/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3177720727043, 24.7756231701321, true, 0, 'Arvukus: 11_100. Iga päev leidub keskmiselt 10-15 suuremat isendit. Tihti on nende juures kümneid pisemaid tigusid.', to_timestamp(1755164311919/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.5546429337441, 25.4360961913999, true, 0, 'Arvukus: 11_100. Krundi taga oleval hooldamata putukaväilä osal on täelik katastroof ja sadu isendeid.', to_timestamp(1755164509146/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4256005945735, 24.6799996703304, true, 0, 'Arvukus: 11_100. Putukaväilal on isendeid sadades. Lisaks liiguvad nad sealt lähikruntidele.', to_timestamp(1755165143037/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3273039436776, 24.8058933718068, true, 0, 'Arvukus: >_100. Hooldamata krunt aadressil Kesk-Vaela 53. Külgnevate kruntide poolt on korjatud ja hävitatud üle 1000 teo', to_timestamp(1755165832527/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.3234542455794, 24.3867674931771, true, 0, 'Arvukus: 2_10. Kollaka limaga ja roheka tooniga limusk.', to_timestamp(1755166978768/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3228302318458, 24.386756764341, true, 0, 'Arvukus: >_100.', to_timestamp(1755167174052/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3113775436275, 24.8366941534158, true, 0, 'Arvukus: 11_100. NB! Ma ei teinud pilti. Leidsin ühe katte alt neid ~6tk. Olen näinud neid ka hoone kõrval. See oli umbes 1kuu tagasi.', to_timestamp(1755167387569/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3431039838027, 24.7866516414269, true, 0, 'Arvukus: >_100.', to_timestamp(1755170998372/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.0121869139799, 27.5441955555699, true, 0, 'Arvukus: >_100.', to_timestamp(1755175084775/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3430745399868, 24.785205273578, true, 0, 'Arvukus: >_100. Esimest aastat. Aastaid olnud Hansaplandi ja Kangru vahelises metsas juid kraav takistas. Nüüd on nad üle ja upume', to_timestamp(1755186012746/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.2967136681622, 24.8485454717066, true, 0, 'Arvukus: 11_100.', to_timestamp(1755189618036/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.5546429337441, 25.4360961913999, true, 0, 'Arvukus: 2_10.', to_timestamp(1755199234069/1000.0)),
