  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.0039888979164, 23.3497141740484, true, 0, 'Arvukus: 1. Leitud kohalikult asfalteelt.', to_timestamp(1755204931474/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.328545583625, 24.8060332995238, true, 0, 'Arvukus: 11_100.', to_timestamp(1755235669953/1000.0)),
