  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.6558967581307, 25.9797661837228, true, 0, 'Arvukus: >_100. Korjasime mitme inimesega tunni aja jooksul 5,5 kg', to_timestamp(1755326838885/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.2683472457162, 23.9666202366371, true, 0, 'Arvukus: >_100.', to_timestamp(1755347744584/1000.0)),
