  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.2554159165618, 22.5032918353115, true, 0, 'Arvukus: 11_100. Kuressaare linn, Raudtee tn 16a ja 16b hooldamata krunt, kust hispaania teeteod tungivad kõrvalaedadesse', to_timestamp(1755430707389/1000.0)),
