  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4216340451656, 24.8068802191349, true, 0, 'Arvukus: 11_100. Rohelistel saartel paksult täis. Teavitssin haldusjuhti.', to_timestamp(1756707910571/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3661036298442, 27.4116108863808, true, 0, 'Arvukus: 2_10.', to_timestamp(1756708176699/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3911600712618, 26.7205594986357, true, 0, 'Arvukus: 1. Võimalik, et neid on juba krundil rohkem, aga praegu nägin ainult ühte.', to_timestamp(1756710483823/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3962828452905, 24.646233122674, true, 0, 'Arvukus: 2_10.', to_timestamp(1756713891552/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3855446611456, 24.8562891849203, true, 0, 'Arvukus: >_100. Korje Roosipõõsa tn.alates Raeküla tee kuni Graniidi teeni (kergliiklus). Kord nädalas kerje, tõrje Iron max Pro lõksudes õllega.', to_timestamp(1756714643591/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3470657662141, 26.7091845007191, true, 0, 'Arvukus: >_100. Kaart lasi märkida ainult ühe leiukoha, kuid tegelikkuses on teeääred täis Kesa, Voolu, Kesa põik, Kopli tänaval.', to_timestamp(1756720466642/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3808500079349, 24.4947335424343, true, 0, 'Arvukus: 1. Tapsin ennem ära kui teatsin et tahate pilti.', to_timestamp(1756721967117/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4244949099355, 24.6348765768663, true, 0, 'Arvukus: 2_10.', to_timestamp(1756732795571/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3808303354403, 26.7467166573114, true, 0, 'Arvukus: >_100.', to_timestamp(1756736596308/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.2950448866921, 26.7197794032361, true, 0, 'Arvukus: >_100. Antud kohas on väga suur arvukus ja ilmselt on seos kõrval oleva prügilaga!Prügila pesks võtma luubi alla ja prügila võiks teostada tõrjet,et antud liik ei leviks kõrval olevatesse küladese!', to_timestamp(1756737460820/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3850329794851, 24.8442174144295, true, 0, 'Arvukus: 11_100. Niidetud muru peal majade ees', to_timestamp(1756744109752/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.341264621351, 24.782413937907, true, 0, 'Arvukus: 2_10.', to_timestamp(1756748008715/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3208796668512, 26.7080893010617, true, 0, 'Arvukus: 2_10.', to_timestamp(1756748462061/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3910956046389, 26.7209190137337, true, 0, 'Arvukus: 2_10.', to_timestamp(1756754046814/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4383325711003, 24.7758188188859, true, 0, 'Arvukus: 2_10. Во время недавних дождей впервые было обнаружено 2 штуки. Фото к сожалению не сделал. Прилагаю наших ёжиков, их к нам заходит штуки 4, для них у нас еды много.', to_timestamp(1756770682834/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.5546429337441, 25.4360961913999, true, 0, 'Arvukus: 2_10. Neid on siin juba mitu aastat', to_timestamp(1756788828989/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3725229008637, 25.5828786852514, true, 0, 'Arvukus: 11_100.', to_timestamp(1756789739275/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3892822530812, 24.6559019623889, true, 0, 'Arvukus: 2_10.', to_timestamp(1756791334041/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.1929047202286, 25.0481486433937, true, 0, 'Arvukus: 11_100. Neid liigub ja on näha kergliiklusteel ja tee ääres rohu sees, niidetud alal. Kui palju neid suure rohu sees on, ei kujutagi ette.', to_timestamp(1756797899246/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.924714, 23.5509668, true, 0, 'Arvukus: 2_10. Nähtud', to_timestamp(1756797997024/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.7430642206606, 26.3985787621006, true, 0, 'Arvukus: 1. Taimepoed peaksid oma kaupa kontrollima!!!', to_timestamp(1756800474095/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3668320498092, 26.9409337613772, true, 0, 'Arvukus: >_100. Naaber sai teada et kortermaja juures on 3ndat aastat tohutu lusitaanlaste populatsioon ja suvel korjas iga õhtu 1,5 t. Mina näen neid tee peale tulemas hommikul mööda jalutan, ja näen nüüd soojemal ajal ca 20 tigu, kellele peale astun.', to_timestamp(1756801607619/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3822735311908, 27.7975005437931, true, 0, 'Arvukus: 11_100.', to_timestamp(1756823831356/1000.0)),
