  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.0018703592116, 27.5409192392565, true, 0, 'Arvukus: 2_10. Pole kindel kas mustpeanälkjas/hispaania teetigu', to_timestamp(1756832330383/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 57.8488013763803, 27.0143954233056, true, 0, 'Arvukus: >_100. Võru linnas, Võrumõisa piirkonnas, linna maal, niitmata võsa, ei suuda invasiooni ohjeldada.', to_timestamp(1756832612972/1000.0)),
