  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3522083042058, 24.5757240256968, true, 0, 'Arvukus: >_100. Umbes seitsme õhtu saak ca 15 liitrit', to_timestamp(1756912745927/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.2986209221644, 24.5946763384131, true, 0, 'Arvukus: 11_100.', to_timestamp(1756965305553/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3501840462553, 26.6720473766258, true, 0, 'Arvukus: >_100. Hispaania teeteod liiguvad kergliiklusteele niitmata alalt tee äärest. Kergliiklusteel on ca 80 m ulatuses võimalik neid vaadelda söömas oma hukkunud liigikaaslasi.', to_timestamp(1756967257489/1000.0)),
