  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3543384228407, 24.5772791737912, true, 0, 'Arvukus: 11_100. Pärnu-Uulu maantee ääres kergliiklusteel palju Hispaania teetigusid, eriti just peale vihmasadusid. Tee ääres rohu sees oli kohati neid ikka väga arvukalt.', to_timestamp(1757048267247/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3801003286876, 24.3047403942403, true, 0, 'Arvukus: >_100.', to_timestamp(1757066681018/1000.0)),
