  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3622849628508, 25.5841835904398, true, 0, 'Arvukus: 11_100. Hävitasin Viljandi vanal kalmistul 16 Hispaania teetigu, neist 7 jäi teele prügikonteinerini. Ei tulnud mõtet pildistada. Järgmisel päeval 30 m pikkusel teekonnal pildistasin, hävitasin 9 tigu. Neid on seal laiemalt kui märge kaardil.', to_timestamp(1757147975677/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3355478339553, 26.6992396240586, true, 0, 'Arvukus: 1.', to_timestamp(1757161326331/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.5546429337441, 25.4360961913999, true, 0, 'Arvukus: 11_100. Tegu metdaradadega majadest mõmekümne meetri kaugusel.', to_timestamp(1757170856835/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.5895833624358, 26.639382321627, true, 0, 'Arvukus: >_100.', to_timestamp(1757178502279/1000.0)),
