  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3475769565251, 26.7373689611773, true, 0, 'Arvukus: >_100. Kõik tee ääred on paksult neid hispaania tigusid täis, üle 100m raadiuses.', to_timestamp(1757234090193/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.28322082678, 26.5386168782314, true, 0, 'Arvukus: 11_100.', to_timestamp(1757244493755/1000.0)),
