  (NULL, 'keskkonnaamet', 'teadmata', 58.3604616990129, 25.6476680122538, true, 0, 'Arvukus: 1.', to_timestamp(1757270985080/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.2397606588154, 22.4925476603641, true, 0, 'Arvukus: >_100. Tuule tn 16 võssa kasvanud krundil terve koloonia, kes varahommikul sealt ümberkaudsetesse aedadesse loivavad.', to_timestamp(1757272674795/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4484316791651, 24.4470624405556, true, 0, 'Arvukus: >_100. Märgitud kohta jõudsid 2025a augustikuu lõpus. 1.sept korjasin üle 300. Murastes, Tuhkru tn lõpus olid teod kohalike sõnul juba varem.', to_timestamp(1757316743356/1000.0)),
