  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3622622132025, 25.5847850165239, true, 0, 'Arvukus: 2_10. Leidsin sellelt teerajalt 14 tigu. Nad kõik said soolakuhjaga kaetud.', to_timestamp(1758551392719/1000.0)),
