  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.5546429337441, 25.4360961913999, true, 0, 'Arvukus: 2_10.', to_timestamp(1758820688507/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4061019515993, 24.6528536106568, true, 0, 'Arvukus: 1.', to_timestamp(1758823921813/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3575308236096, 24.5831155146394, true, 0, 'Arvukus: >_100. Käin korjamas nii haljakul kui jõeäärses metsas, sest ka metsa alt leiab neid päris palju.', to_timestamp(1758826409648/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.9439383280315, 23.5457271715945, true, 0, 'Arvukus: 2_10. Pilt teost tehtud ja kustutatud. Soolvette pandud 3 isendit. Teavituse teen seetõttu ilma pildita, kuid vähemalt on teada antud.', to_timestamp(1758828520252/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.5546429337441, 25.4360961913999, true, 0, 'Arvukus: >_100.', to_timestamp(1758859325080/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.2390002441605, 24.676748602118, true, 0, 'Arvukus: 11_100.', to_timestamp(1758863692112/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.4362656171309, 28.0039334724298, true, 0, 'Arvukus: 2_10. Terve keerliiklustee peal', to_timestamp(1758867683363/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3377577993598, 24.2959046522999, true, 0, 'Arvukus: 11_100.', to_timestamp(1758868506987/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.5513786550137, 26.6003355994751, true, 0, 'Arvukus: 2_10.', to_timestamp(1758876147217/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.44281492822, 24.4801556526125, true, 0, 'Arvukus: >_100.', to_timestamp(1758887228181/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.4036352690514, 26.7339118516, true, 0, 'Arvukus: 11_100. Märgitud asukohal on üks õunapuu, mille all oleme neid tigusid kokku loendanud üle 15-ne. Kuna maalapp ei kuulu justkui kellelegi, siis ilmselt ei tegele keegi seal ka võõrliigi hävitamisega.', to_timestamp(1758895981288/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.4934857825902, 26.7689685758163, true, 0, 'Arvukus: 1. Aiamaadele viiva niidetud tee kõrval on aiajäätmed, nende juures oli näha ühte, kes oli niidetud murule roomanud', to_timestamp(1758896783119/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.373679750773, 26.7325074815808, true, 0, 'Arvukus: >_100. Mitmendat suve on videvikus näha palju murus ja maja ümber Hispaania teetigusid. Kortermaja, 13 korterit. Ühistu pole eriti tegus, s.h. nälkjaid ei tõrju. Majas 99.9% üürnikud, enamus tudengid. 1 in. vahel korjab tigusid.', to_timestamp(1758914183202/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.3202971701044, 26.7068978274979, true, 0, 'Arvukus: 2_10. Päevas leiab 2-4 tk', to_timestamp(1758956417908/1000.0)),
