  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.5546429337441, 25.4360961913999, true, 0, 'Arvukus: >_100. Pildil on kodumaised teod, teadlikult ma neid ei hävita,vaid poputan!', to_timestamp(1761981271291/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.2546406508461, 25.972123646149, true, 0, 'Arvukus: 11_100. Umbes 5min jooksul nägin 7 isendit, lisaks oli veel varem tapetud isendeid.', to_timestamp(1762010936747/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3265812664313, 26.2534694876307, true, 0, 'Arvukus: 2_10. Leitud talu õuest, lillepeenrast 5 isendit.', to_timestamp(1762125153729/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.3735778551376, 24.7331377677368, true, 0, 'Arvukus: 2_10. Kunagi ei ole Liiva kalmistul nälkjaid näinud. Matsikoht R, U I, 3-2 On ka helesinakad', to_timestamp(1762622706923/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3068947406983, 24.532471217463, true, 0, 'Arvukus: 2_10. Avastasime 1. juulil 2025', to_timestamp(1762706772374/1000.0)),
