  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.5567715957559, 25.9053495088151, true, 0, 'Arvukus: >_100. Korjasin kevadest alates kuni lumeni iga päev tk. Viimase leidsin.', to_timestamp(1764341549808/1000.0)),
  (NULL, 'keskkonnaamet', 'teadmata', 59.4215968295848, 24.6998857880011, true, 0, 'Arvukus: 11_100. 2025 suve keskpaigast saati leitud hunnik suuri seatigusid', to_timestamp(1766398953878/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.2581422445936, 25.0103847047334, true, 0, 'Arvukus: >_100. hommikul ja õhtul 100tk vabalt voimalik korjata', to_timestamp(1772612362409/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3428078699282, 24.9035119862966, true, 0, 'Arvukus: >_100. Kogu Aaviku tee äär, terve Heina tänava tagune kraav ja Tartu mnt äärne põld on tigusid täis. Teod tungivad avalikelt aladelt aedadesse.', to_timestamp(1772633310970/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.5546429337441, 25.4360961913999, true, 0, 'Arvukus: >_100. Päris palju,juba umbes 7 aastad võitlen nendega,pilte ei ole - märtsi algus,magavad veel', to_timestamp(1772634808683/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.389364244132, 24.7987438295031, true, 0, 'Arvukus: 11_100.', to_timestamp(1772730390928/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3735485837722, 24.8372472660383, true, 0, 'Arvukus: >_100. Põld/kraavid/metsatukk täis neid. Tungivad aedadesse. Silvia tänava poolt tulevad.', to_timestamp(1772785418742/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3887171690119, 24.8584776723166, true, 0, 'Arvukus: >_100.', to_timestamp(1773009597714/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3885861101507, 24.9549297825224, true, 0, 'Arvukus: >_100. Tegime korjeid süstemaatiliselt 1-3 korda päevas ja igapäevaselt. Krundi vastast pölluserva muruäärisest tuvastasime meeletus koguses. Jätkasime korjega kuni esimeste külmadeni. Leidsin möned isendid isegi novembris vösast.', to_timestamp(1773624188930/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3895583061453, 24.6440399646033, true, 0, 'Arvukus: >_100.', to_timestamp(1774855646131/1000.0)),
