  (NULL, 'keskkonnaamet', 'arion_vulgaris', 57.8612878489593, 27.2221544604852, true, 0, 'Arvukus: 1. Leidsin.a. sügisel, õhtul kell 20:09 kui ta sõi minu kõrvtsa suuri lehti. Tegelikult oli ta veel pikem, aga pildistamise hetkel oli ehmunud.', to_timestamp(1777923362895/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 58.5556415463753, 23.0774800297202, true, 0, 'Arvukus: >_100. Ei saa hetkel pilti lisada, aga tigusid on PALJU ning tegemist on RIIGI maaga!!!', to_timestamp(1778675766598/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.2036453417914, 24.6644568443237, true, 0, 'Arvukus: 2_10.', to_timestamp(1778692748022/1000.0)),
  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.3545408311088, 26.3732259191448, true, 0, 'Arvukus: 11_100. Praegu hakkasid selle aasta omad tulema ja eelmine aasta oli neid miljoni. Seega varsti jälle upume neisse.', to_timestamp(1778696060702/1000.0)),
