  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.493729087493, 24.866152021097, true, 0, 'Arvukus: >_100. Väga suures koguses kõikjal raudtee ümbruses.', to_timestamp(1779298644512/1000.0)),
