  (NULL, 'keskkonnaamet', 'arion_vulgaris', 59.396663, 24.291925, true, 0, 'Arvukus: 11_100. Leitud suur hispaania teetigude kogum niiskel samblal ja kõdunenud puidul; võimalik varjumis- või pesitsuskoht.', to_timestamp(1781431672188/1000.0)),
